function updDots(){
  var row=document.getElementById('dots-row');
  if(!row)return;
  // Show dots for all weeks up to current + a few ahead
  var maxW=Math.max(17,cw+3);
  var html='';
  for(var w=1;w<=maxW;w++){
    var s=ws(w),d=Object.values(s.wo).filter(Boolean).length;
    var wc=getWC(w)||6;
    var cls='dot'+(w===cw?' cur':(d>=wc&&wc>0?' done':''));
    html+='<div class="'+cls+'" onclick="GW('+w+', true)" title="Week '+w+'"></div>';
  }
  row.innerHTML=html;
}

