// Computes a comparable training-stress number for any activity type.
// Cycling activities with power data already have a real TSS (Coggan formula).
// Everything else (runs, strength, mobility, etc.) falls back to:
//   1. hrTSS - based on avg HR relative to estimated lactate threshold HR
//      (LTHR estimated as 88% of max HR when not otherwise known - a standard
//      approximation, per Friel, when no formal threshold test exists)
//   2. RPE x duration (Foster's session-RPE method) when no HR data exists
// This lets one CTL/ATL/TSB model represent total load across every sport,
// since fatigue from running affects cycling performance and vice versa.
function unifiedLoad(a){
  if(a.tss) return a.tss; // already has real power-based TSS (cycling)

  var durMin = (a.movingSecs ? a.movingSecs/60 : (a.duration ? parseDurToMin(a.duration) : 0));
  var maxHR = parseInt(st.maxHR||172);
  var lthr = Math.round(maxHR*0.88);

  if(a.avgHR && durMin){
    // hrTSS: scales duration by intensity relative to threshold HR, using
    // an exponential weighting similar to TrainingPeaks' hrTSS approach
    var hrRatio = a.avgHR/lthr;
    var intensityFactor = Math.min(1.15, hrRatio); // cap runaway values from anomalous HR spikes
    return Math.round(durMin * intensityFactor * intensityFactor * 100/60);
  }

  if(a.rpe && durMin){
    // Foster session-RPE: duration (min) x RPE (1-10), scaled to sit on a
    // comparable numeric range to cycling TSS (roughly /3)
    return Math.round((durMin * a.rpe) / 3);
  }

  return 0;
}

function parseDurToMin(durStr){
  if(!durStr) return 0;
  var parts = String(durStr).split(':').map(Number);
  if(parts.length===3) return parts[0]*60+parts[1]+parts[2]/60;
  if(parts.length===2) return parts[0]+parts[1]/60;
  return parseFloat(durStr)||0;
}

// Events: real, editable race/goal-date entries, replacing the old
// hardcoded "Grand Rapids Half, Oct 18" date with a proper st.events array.
function ensureEvents(){
  if(!st.events){
    st.events = [
      {id:'evt-'+Date.now(), name:'Grand Rapids Half Marathon', date:'2026-10-18', type:'race'}
    ];
    sv();
  }
}

function eventsCardHTML(){
  ensureEvents();
  var today = new Date(); today.setHours(0,0,0,0);
  var upcoming = (st.events||[]).map(function(e){
    var d = new Date(e.date+'T00:00:00');
    var daysOut = Math.ceil((d-today)/(1000*60*60*24));
    return {evt:e, daysOut:daysOut};
  }).filter(function(x){ return x.daysOut >= 0; })
    .sort(function(a,b){ return a.daysOut - b.daysOut; });

  if(!upcoming.length) return '';
  var next = upcoming[0];
  var weeksOut = Math.floor(next.daysOut/7);

  return '<div style="margin:0 16px 12px;background:linear-gradient(135deg,rgba(15,110,86,.12),rgba(15,110,86,.04));border:1px solid rgba(15,110,86,.25);border-radius:14px;padding:14px 16px">'
    + '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#0F6E56;margin-bottom:4px">'+(next.evt.type==='race'?'🏁':'📅')+' '+next.evt.name+'</div>'
    + '<div style="display:flex;align-items:baseline;gap:8px">'
    + '<div style="font-size:28px;font-weight:900;color:var(--t1)">'+next.daysOut+'</div>'
    + '<div style="font-size:13px;color:var(--t2)">days out · '+weeksOut+' weeks</div>'
    + '</div></div>';
}

function openEventEdit(){
  var modal = document.getElementById('mod-SERVICE');
  modal.innerHTML = '';
  modal.style.cssText = 'align-items:center;justify-content:center;padding:20px';

  var card = document.createElement('div');
  card.style.cssText = 'background:var(--s1);border-radius:16px;width:100%;max-width:320px;padding:22px 20px;box-shadow:0 8px 32px rgba(0,0,0,.3)';

  var title = document.createElement('div');
  title.style.cssText = 'font-size:17px;font-weight:800;color:var(--t1);margin-bottom:16px';
  title.textContent = 'Add Event';
  card.appendChild(title);

  function makeField(labelText, placeholder, type, defaultVal){
    var wrap = document.createElement('div');
    wrap.style.cssText = 'margin-bottom:12px';
    var lbl = document.createElement('div');
    lbl.style.cssText = 'font-size:12px;font-weight:600;color:var(--t3);margin-bottom:5px';
    lbl.textContent = labelText;
    var input = document.createElement('input');
    input.type = type||'text';
    input.placeholder = placeholder||'';
    if(defaultVal!=null) input.value = defaultVal;
    input.style.cssText = 'width:100%;padding:10px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:10px;color:var(--t1);font-size:14px;font-family:inherit';
    wrap.appendChild(lbl);
    wrap.appendChild(input);
    card.appendChild(wrap);
    return input;
  }

  var nameInput = makeField('Event name', 'e.g. Grand Rapids Half');
  var dateInput = makeField('Date', 'YYYY-MM-DD', 'date');

  var typeWrap = document.createElement('div');
  typeWrap.style.cssText = 'margin-bottom:12px';
  var typeLbl = document.createElement('div');
  typeLbl.style.cssText = 'font-size:12px;font-weight:600;color:var(--t3);margin-bottom:5px';
  typeLbl.textContent = 'Type';
  var typeSelect = document.createElement('select');
  typeSelect.style.cssText = 'width:100%;padding:10px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:10px;color:var(--t1);font-size:14px;font-family:inherit';
  ['race','goal'].forEach(function(opt){
    var o = document.createElement('option'); o.value = opt; o.textContent = opt==='race'?'Race':'Goal'; typeSelect.appendChild(o);
  });
  typeWrap.appendChild(typeLbl); typeWrap.appendChild(typeSelect);
  card.appendChild(typeWrap);

  var actions = document.createElement('div');
  actions.style.cssText = 'display:flex;gap:8px;margin-top:8px';

  var cancelBtn = document.createElement('button');
  cancelBtn.textContent = 'Cancel';
  cancelBtn.style.cssText = 'flex:1;padding:11px;background:var(--s2);border:1px solid var(--b1);border-radius:10px;color:var(--t1);font-size:14px;font-weight:700;cursor:pointer';
  cancelBtn.addEventListener('click', function(){ closeServiceModal(); });

  var saveBtn = document.createElement('button');
  saveBtn.textContent = 'Add Event';
  saveBtn.style.cssText = 'flex:1;padding:11px;background:#FC4C02;border:none;border-radius:10px;color:#fff;font-size:14px;font-weight:700;cursor:pointer';
  saveBtn.addEventListener('click', function(){
    var name = nameInput.value.trim();
    if(!name){ nameInput.style.borderColor='#E24B4A'; return; }
    var dateStr = dateInput.value;
    if(!dateStr || !/^\\d{4}-\\d{2}-\\d{2}$/.test(dateStr)){ dateInput.style.borderColor='#E24B4A'; return; }
    ensureEvents();
    st.events.push({id:'evt-'+Date.now(), name:name, date:dateStr, type:typeSelect.value});
    sv();
    closeServiceModal();
    renderHomeTSSAndPR();
    toast('Event added');
  });

  actions.appendChild(cancelBtn);
  actions.appendChild(saveBtn);
  card.appendChild(actions);

  modal.appendChild(card);
  modal.classList.add('open');
  document.body.style.overflow = 'hidden';
}

// Achievements: real PR history instead of only-detects-if-happened-today
// logic, plus a simple streak counter. Existing longest-ride/best-NP/highest-TSS
// detection logic (from the disabled home function) is reused here, now
// feeding a persistent st.achievements log instead of a transient banner.
function checkForNewAchievements(){
  var rides = (st.rides||[]).filter(function(r){ return !r.deleted; });
  if(!rides.length) return;
  if(!st.achievements) st.achievements = [];

  var longestRide=0, bestNP=0, highestTSS=0;
  // Sanity ceilings: values above these are corrupted/malformed data, not
  // real rides. NP above 600W and TSS above 600 are outside anything a real
  // human ride produces (even elite pro efforts), so we exclude them rather
  // than let a bad data point post a bogus PR banner.
  var NP_CEILING = 600, TSS_CEILING = 600;
  rides.forEach(function(r){
    if(parseFloat(r.distance||0)>longestRide) longestRide=parseFloat(r.distance||0);
    if(r.np && r.np>bestNP && r.np<=NP_CEILING) bestNP=r.np;
    if(r.tss && r.tss>highestTSS && r.tss<=TSS_CEILING) highestTSS=r.tss;
  });

  function recordIfNew(key, label, value){
    var existing = st.achievements.find(function(a){ return a.key===key; });
    if(!existing || value > existing.value){
      st.achievements = st.achievements.filter(function(a){ return a.key!==key; });
      st.achievements.unshift({key:key, label:label, value:value, date:getTodayKey()});
      return true;
    }
    return false;
  }

  var changed = false;
  if(longestRide>0) changed = recordIfNew('longest_ride', 'Longest ride: '+longestRide.toFixed(1)+' mi', longestRide) || changed;
  if(bestNP>0) changed = recordIfNew('best_np', 'Best NP: '+bestNP+'W', bestNP) || changed;
  if(highestTSS>0) changed = recordIfNew('highest_tss', 'Highest TSS: '+highestTSS, highestTSS) || changed;

  if(changed) sv();
}

function achievementsCardHTML(){
  checkForNewAchievements();
  if(!st.achievements || !st.achievements.length) return '';
  var today = getTodayKey();
  var newToday = st.achievements.filter(function(a){ return a.date===today; });
  if(!newToday.length) return '';

  var h = '<div style="margin:0 16px 12px;background:var(--s2);border-radius:14px;padding:12px 14px">'
    + '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#FC4C02;margin-bottom:6px">🏆 New Personal Record!</div>';
  newToday.forEach(function(a){
    h += '<div style="font-size:13px;font-weight:700;color:var(--t1);padding:2px 0">'+a.label+'</div>';
  });
  h += '</div>';
  return h;
}

