// Weather + Form stat row - two-up cards matching the visual weight of
// "the two numbers that most determine today's ride." Weather tile is
// clickable and jumps straight to the full Weather screen (showWeather()).
function weatherFormRowHTML(){
  var wxId = 'wx-stat-'+Date.now();

  var activitiesForForm = (st.rides||[]).filter(function(r){ return !r.deleted; })
    .concat((st.runs||[]).map(function(r){ return {date:r.date, avgHR:r.avgHR, duration:r.time, rpe:r.rpe, deleted:false}; }));
  activitiesForForm.forEach(function(a){ a.load = unifiedLoad(a); });
  var withLoad = activitiesForForm.filter(function(a){ return a.load>0; });
  var formHTML;
  if(withLoad.length < 5){
    formHTML = '<div style="font-size:13px;color:var(--t2);margin-top:2px">Log more rides for a form reading</div>';
  } else {
    var pmc = computePMC(withLoad);
    var tsb = Math.round(pmc[pmc.length-1].ctl - pmc[pmc.length-1].atl);
    var formColor = tsb >= 10 ? '#5DCAA5' : tsb >= -10 ? '#4D9FFF' : tsb >= -25 ? '#EF9F27' : '#E24B4A';
    var formLabel = tsb >= 10 ? 'Fresh, good day to push' : tsb >= -10 ? 'Steady state' : tsb >= -25 ? 'Fatigue building' : 'Prioritize recovery';
    formHTML = '<div style="font-size:20px;font-weight:800;color:'+formColor+'">'+(tsb>=0?'+':'')+tsb+'</div>'
      + '<div style="font-size:11px;color:var(--t2);margin-top:2px">'+formLabel+'</div>';
  }

  fetch('https://api.open-meteo.com/v1/forecast?latitude=42.9634&longitude=-85.6681'
    +'&current=temperature_2m,windspeed_10m,precipitation_probability'
    +'&temperature_unit=fahrenheit&windspeed_unit=mph&timezone=America%2FChicago&forecast_days=1')
  .then(function(r){ return r.json(); })
  .then(function(d){
    var el = document.getElementById(wxId);
    if(!el || !d.current) return;
    var temp = Math.round(d.current.temperature_2m);
    var wind = Math.round(d.current.windspeed_10m);
    var rain = d.current.precipitation_probability;
    el.innerHTML = '<div style="font-size:20px;font-weight:800;color:var(--t1)">'+temp+'&deg;</div>'
      + '<div style="font-size:11px;color:var(--t2);margin-top:2px">Wind '+wind+'mph'+(rain!=null?' &middot; '+rain+'% rain':'')+'</div>';
  }).catch(function(){
    var el = document.getElementById(wxId);
    if(el) el.innerHTML = '<div style="font-size:13px;color:var(--t3)">Weather unavailable</div>';
  });

  return '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:0 16px 14px">'
    + '<div id="'+wxId+'" onclick="showWeather()" style="background:var(--s2);border-radius:14px;padding:12px 14px;cursor:pointer">'
    + '<div style="font-size:10px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px">Weather</div>'
    + 'Loading&hellip;</div>'
    + '<div style="background:var(--s2);border-radius:14px;padding:12px 14px">'
    + '<div style="font-size:10px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px">Form</div>'
    + formHTML
    + '</div></div>';
}

// Live AI-generated coach note - the hero card on Home. Fresh every visit
// (no caching), same context model as the full AI Coach screen but
// condensed to 1-2 sentences. Given hero visual treatment (purple-tinted,
// largest text on the page) since it's the single most important thing to
// read at a glance.
function coachNoteHTML(){
  var id = 'coach-note-'+Date.now();
  setTimeout(function(){ fetchCoachNote(id); }, 0);
  return '<div style="margin:0 16px 14px;background:linear-gradient(135deg,rgba(168,85,247,.14),rgba(168,85,247,.03));border:1px solid rgba(168,85,247,.28);border-radius:18px;padding:16px 18px">'
    + '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#c084fc;margin-bottom:8px">Coach</div>'
    + '<div id="'+id+'" style="font-size:17px;font-weight:600;color:var(--t1);line-height:1.35">Thinking&hellip;</div>'
    + '</div>';
}

function fetchCoachNote(elId){
  var el = document.getElementById(elId);
  if(!el) return;

  fetch('https://api.open-meteo.com/v1/forecast?latitude=42.9634&longitude=-85.6681'
    +'&current=temperature_2m,windspeed_10m,winddirection_10m,precipitation_probability'
    +'&temperature_unit=fahrenheit&windspeed_unit=mph&timezone=America%2FChicago&forecast_days=1')
  .then(function(r){ return r.json(); })
  .then(function(wxData){
    var wx = wxData && wxData.current;
    var weatherStr = wx
      ? Math.round(wx.temperature_2m)+'F, wind '+Math.round(wx.windspeed_10m)+'mph from '+['N','NE','E','SE','S','SW','W','NW'][Math.round((wx.winddirection_10m||0)/45)%8]+(wx.precipitation_probability!=null?', '+wx.precipitation_probability+'% rain':'')
      : 'unavailable';

    fetchTodaysDecision(weatherStr, function(err, decisionText){
      var target = document.getElementById(elId);
      if(!target) return;
      target.textContent = (err || !decisionText) ? 'Coach unavailable right now.' : decisionText;
    });
  })
  .catch(function(){
    fetchTodaysDecision('unavailable', function(err, decisionText){
      var target = document.getElementById(elId);
      if(!target) return;
      target.textContent = (err || !decisionText) ? 'Coach unavailable right now.' : decisionText;
    });
  });
}

// Today's single workout card - clones today's real wo-card from the full
// week view (with its live checkbox/swap/log buttons intact) rather than
// rebuilding workout logic separately, so behavior stays identical. Given a
// left accent bar to read as "the next action," distinct from the stat cards.
function todayWorkoutHTML(){
  var today = new Date();
  var todayIdx = today.getDay()===0 ? 6 : today.getDay()-1;
  var sourceCard = document.getElementById('wc'+cw+'_'+todayIdx);
  var label = '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);margin:0 16px 8px">Today</div>';
  if(!sourceCard){
    return label + '<div style="margin:0 16px 14px;background:var(--s2);border-radius:14px;padding:20px;text-align:center;border-left:3px solid var(--b1)">'
      + '<div style="font-size:14px;color:var(--t2)">No workout scheduled today</div></div>';
  }
  var clone = sourceCard.cloneNode(true);
  clone.removeAttribute('id');
  var innerIds = clone.querySelectorAll('[id]');
  innerIds.forEach(function(el){ el.id = 'today-clone-'+el.id; });
  clone.style.borderLeft = '3px solid #FC4C02';
  clone.style.borderTopLeftRadius = '4px';
  clone.style.borderBottomLeftRadius = '4px';
  var wrapper = document.createElement('div');
  wrapper.appendChild(clone);
  return label + wrapper.innerHTML;
}

// Weight + Nutrition secondary stat row - demoted below Today since these
// are check-ins, not the day's main decision.
function weightNutritionRowHTML(){
  var wLog = st.weightLog||[];
  var latestW = wLog.length ? wLog[wLog.length-1] : null;
  var tots = getDTots(getTodayKey());

  var weightTile = '<div style="background:var(--s2);border-radius:14px;padding:12px 14px">'
    + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:2px">'
    + '<div style="font-size:10px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em">Weight</div>'
    + '<button onclick="logWeightQuick()" style="background:none;border:none;color:#FC4C02;font-size:11px;font-weight:700;cursor:pointer;padding:0">+ Log</button>'
    + '</div>'
    + '<div style="font-size:16px;font-weight:800;color:var(--t1)">'+(st.weight?st.weight+' lbs':'—')+'</div>'
    + '</div>';

  var nutritionTile = tots.cal
    ? '<div onclick="showNutr()" style="background:var(--s2);border-radius:14px;padding:12px 14px;cursor:pointer">'
      + '<div style="font-size:10px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:2px">Nutrition</div>'
      + '<div style="font-size:16px;font-weight:800;color:var(--t1)">'+Math.round(tots.cal)+' cal</div>'
      + '</div>'
    : '<div onclick="showNutr()" style="background:var(--s2);border-radius:14px;padding:12px 14px;cursor:pointer;display:flex;align-items:center">'
      + '<div style="font-size:12px;color:#FC4C02;font-weight:700">Log food</div>'
      + '</div>';

  return '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:0 16px 14px">'+weightTile+nutritionTile+'</div>';
}

function readinessCardHTML(){
  var activities = (st.rides||[]).filter(function(r){ return !r.deleted; })
    .concat((st.runs||[]).map(function(r){ return {date:r.date, avgHR:r.avgHR, duration:r.time, rpe:r.rpe, deleted:false}; }));
  activities.forEach(function(a){ a.load = unifiedLoad(a); });
  var withLoad = activities.filter(function(a){ return a.load>0; });

  if(withLoad.length < 5){
    return '<div style="margin:0 16px 12px;background:var(--s2);border-radius:14px;padding:14px 16px">'
      + '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);margin-bottom:4px">Training load</div>'
      + '<div style="font-size:14px;color:var(--t2)">Log a few more sessions to see your readiness signal</div>'
      + '</div>';
  }

  var pmc = computePMC(withLoad);
  var today = pmc[pmc.length-1];
  var fitness = today.ctl, fatigue = today.atl, form = today.tsb;

  var headline, sub, badgeLabel, badgeColor, badgeText;
  if(form >= 10){
    headline = 'Good day to push'; sub = 'Form is positive — fatigue is well below fitness';
    badgeLabel='Fresh'; badgeColor='#5DCAA522'; badgeText='#5DCAA5';
  } else if(form >= -10){
    headline = 'Steady state'; sub = 'Fitness and fatigue are close — normal training day';
    badgeLabel='Balanced'; badgeColor='#4D9FFF22'; badgeText='#4D9FFF';
  } else if(form >= -25){
    headline = 'Fatigue is building'; sub = 'Consider an easier day or shorter intervals';
    badgeLabel='Loaded'; badgeColor='#EF9F2722'; badgeText='#EF9F27';
  } else {
    headline = 'Fatigue is high'; sub = 'Recent training load is heavy — prioritize recovery';
    badgeLabel='Fatigued'; badgeColor='#E24B4A22'; badgeText='#E24B4A';
  }

  return '<div style="margin:0 16px 12px;background:var(--s2);border-radius:16px;padding:16px">'
    + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">'
    + '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3)">Training load</div>'
    + '<div style="background:'+badgeColor+';color:'+badgeText+';font-size:11px;font-weight:700;padding:4px 10px;border-radius:20px">'+badgeLabel+'</div>'
    + '</div>'
    + '<div style="font-size:18px;font-weight:800;color:var(--t1);margin-bottom:4px">'+headline+'</div>'
    + '<div style="font-size:13px;color:var(--t2);margin-bottom:14px">'+sub+'</div>'
    + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px">'
    + '<div style="background:var(--s3);border-radius:10px;padding:10px"><div style="font-size:10px;color:var(--t3);margin-bottom:2px">FITNESS</div><div style="font-size:16px;font-weight:800;color:var(--t1)">'+Math.round(fitness)+'</div></div>'
    + '<div style="background:var(--s3);border-radius:10px;padding:10px"><div style="font-size:10px;color:var(--t3);margin-bottom:2px">FATIGUE</div><div style="font-size:16px;font-weight:800;color:var(--t1)">'+Math.round(fatigue)+'</div></div>'
    + '<div style="background:var(--s3);border-radius:10px;padding:10px"><div style="font-size:10px;color:var(--t3);margin-bottom:2px">FORM</div><div style="font-size:16px;font-weight:800;color:'+badgeText+'">'+(form>=0?'+':'')+Math.round(form)+'</div></div>'
    + '</div></div>';
}

function renderHomeTSSAndPR(){
  var container = document.getElementById('home-tss-pr');
  if(!container) return;
  container.innerHTML = greetingHTML()
    + coachNoteHTML()
    + weatherFormRowHTML()
    + todayWorkoutHTML()
    + weightNutritionRowHTML()
    + eventsCardHTML()
    + achievementsCardHTML();
  return; // rest of function disabled - duplicated on Progress screen
  var rides = st.rides||[];

  // Weight quick-log button (always shown, independent of rides)
  var wLog = st.weightLog||[];
  var latestW = wLog.length ? wLog[wLog.length-1] : null;
  var weightHtml = '<div style="margin:0 16px 12px;background:var(--s2);border-radius:14px;padding:12px 14px;display:flex;align-items:center;justify-content:space-between">'
    + '<div><div style="font-size:11px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.06em">Weight</div>'
    + '<div style="font-size:18px;font-weight:800;color:var(--t1);margin-top:2px">'+(st.weight?st.weight+' lbs':'—')+(latestW?' <span style="font-size:11px;font-weight:600;color:var(--t3)">('+latestW.date+')</span>':'')+'</div></div>'
    + '<button onclick="logWeightQuick()" style="background:linear-gradient(135deg,#FC4C02,#FF7043);border:none;color:white;font-size:12px;font-weight:700;padding:9px 16px;border-radius:10px;cursor:pointer;font-family:inherit">+ Log</button>'
    + '</div>';

  // Half Marathon countdown (Grand Rapids Half, Oct 18)
  var raceDate = new Date(new Date().getFullYear(), 9, 18); // Oct 18
  var todayD = new Date(); todayD.setHours(0,0,0,0);
  if(raceDate < todayD) raceDate.setFullYear(raceDate.getFullYear()+1);
  var daysOut = Math.ceil((raceDate-todayD)/(1000*60*60*24));
  var weeksOut = Math.floor(daysOut/7);
  weightHtml += '<div style="margin:0 16px 12px;background:linear-gradient(135deg,rgba(15,110,86,.12),rgba(15,110,86,.04));border:1px solid rgba(15,110,86,.25);border-radius:14px;padding:14px">'
    + '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#0F6E56;margin-bottom:4px">🏃 Grand Rapids Half Marathon</div>'
    + '<div style="display:flex;align-items:baseline;gap:8px">'
    + '<div style="font-size:28px;font-weight:900;color:var(--t1)">'+daysOut+'</div>'
    + '<div style="font-size:13px;color:var(--t2)">days out · '+weeksOut+' weeks</div>'
    + '</div></div>';

  if(!rides.length){ container.innerHTML=weightHtml; return; }

  var longestRide=0,bestNP=0,highestTSS=0;
  var weekTSSmap2={};
  var now2=new Date();
  rides.forEach(function(r){
    if(parseFloat(r.distance||0)>longestRide) longestRide=parseFloat(r.distance||0);
    if(r.np&&r.np>bestNP) bestNP=r.np;
    if(r.tss&&r.tss>highestTSS) highestTSS=r.tss;
    if(r.date&&r.tss){
      var wk=getWeekKey(new Date(r.date));
      weekTSSmap2[wk]=(weekTSSmap2[wk]||0)+(r.tss||0);
    }
  });
  var wTSSLabels2=[],wTSSData2=[];
  for(var wi2=7;wi2>=0;wi2--){
    var wd2=new Date(now2); wd2.setDate(now2.getDate()-wi2*7);
    var wk2=getWeekKey(wd2);
    var mo=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][wd2.getMonth()];
    wTSSLabels2.push(mo+' '+wd2.getDate());
    wTSSData2.push(Math.round(weekTSSmap2[wk2]||0));
  }
  var maxTSS2=Math.max.apply(null,wTSSData2)||1;
  var recentPRs=[];
  var sevenDaysAgo=new Date(now2); sevenDaysAgo.setDate(now2.getDate()-7);
  var recentRides=rides.filter(function(r){return r.date&&new Date(r.date)>=sevenDaysAgo;});
  recentRides.forEach(function(r){
    if(r.distance&&parseFloat(r.distance)===longestRide) recentPRs.push('🏅 Longest ride: '+longestRide.toFixed(1)+' mi');
    if(r.np&&r.np===bestNP) recentPRs.push('⚡ Best NP: '+bestNP+'W');
    if(r.tss&&r.tss===highestTSS) recentPRs.push('🔥 Highest TSS: '+highestTSS);
  });

  var h='';
  h+='<div style="margin:0 16px 12px;background:var(--s2);border-radius:14px;padding:14px">';
  h+='<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:10px">';
  h+='<div style="font-size:12px;font-weight:700;color:var(--t1)">Weekly TSS</div>';
  h+='<div style="font-size:11px;color:var(--t3)">This week: '+wTSSData2[7]+'</div></div>';
  h+='<div style="display:flex;align-items:flex-end;gap:4px;height:60px">';
  wTSSData2.forEach(function(v,i){
    var pct=Math.round((v/maxTSS2)*100);
    var isThisWeek=i===7;
    var barColor=isThisWeek?'#FC4C02':'rgba(252,76,2,.35)';
    h+='<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">';
    h+='<div style="width:100%;background:'+barColor+';border-radius:3px 3px 0 0;height:'+pct+'%;min-height:'+(v>0?'3':'0')+'px"></div>';
    h+='<div style="font-size:8px;color:var(--t3);white-space:nowrap;overflow:hidden;text-overflow:clip">'+wTSSLabels2[i].split(' ')[0]+'</div>';
    h+='</div>';
  });
  h+='</div></div>';

  if(recentPRs.length){
    h+='<div style="margin:0 16px 12px;background:linear-gradient(135deg,rgba(252,76,2,.15),rgba(252,76,2,.05));border:1px solid rgba(252,76,2,.3);border-radius:14px;padding:12px 14px">';
    h+='<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#FC4C02;margin-bottom:6px">🏆 New Personal Record!</div>';
    recentPRs.forEach(function(pr){
      h+='<div style="font-size:13px;font-weight:700;color:var(--t1);padding:2px 0">'+pr+'</div>';
    });
    h+='</div>';
  }

  container.innerHTML = weightHtml + h;
}

function GW(w, revealWeek){
  if(w<1)return;
  var old=document.getElementById('W'+cw);
  if(old)old.style.display='none';
  cw=w;
  var nw=document.getElementById('W'+w);
  if(nw){
    // Only actually show the full week schedule block when explicitly
    // requested (e.g. tapping a planned day in Calendar). Normal app
    // loads/syncs call GW() constantly just to keep cw and the dashboard
    // (renderHomeTSSAndPR) current - showing the week block every time
    // that happens is what caused the full week to always be visible on
    // Home, defeating the point of the redesigned single-day dashboard.
    nw.style.display = revealWeek ? 'block' : 'none';
  } else {
    if(revealWeek) renderDynWeek(w);
  }
  showTrain();
  renderHomeTSSAndPR();
  updHdr();
  updDots();
  restoreW(w);
  try{injectRideStats(w);}catch(e){console.error('injectRideStats:',e);}
  window.scrollTo(0,0);
  closePk();
}

function renderDynWeek(w){
  // Weeks beyond the original 17-week plan use week 1's structure (a normal
  // training week: Strength/Zwift/Group Ride/Rest) as an ongoing maintenance
  // template - NOT week 17, which is race week and was being repeated
  // (including its literal "RACE DAY" session) for every week thereafter.
  var base=document.getElementById('W1');
  if(!base)return;
  var clone=base.cloneNode(true);
  clone.id='W'+w;
  clone.style.display='none';
  // Update all IDs to use new week number
  var html=clone.outerHTML;
  html=html.replace(/id="([a-zA-Z]+)1_/g,'id="$1'+w+'_');
  html=html.replace(/id="([a-zA-Z]+)1"/g,'id="$1'+w+'"');
  html=html.replace(/TW\\(1,/g,'TW('+w+',');
  html=html.replace(/TN\\(1,/g,'TN('+w+',');
  html=html.replace(/SF\\(1,/g,'SF('+w+',');
  html=html.replace(/SC\\(1,/g,'SC('+w+',');
  html=html.replace(/openStr\\('([AB])',1\\)/g,"openStr('$1',"+w+')');
  html=html.replace(/doSwap\\(1,/g,'doSwap('+w+',');
  html=html.replace(/saveNT\\(1,/g,'saveNT('+w+',');
  html=html.replace(/End of Week 1\\b/g,'End of Week '+w);
  // Wrap and insert
  var tmp=document.createElement('div');
  tmp.innerHTML=html;
  var newWeek=tmp.firstChild;
  newWeek.id='W'+w;
  document.getElementById('W1').parentNode.appendChild(newWeek);
}

function showTrain(){
  // Only force TRAIN visible if it's already the active screen - this
  // function is called routinely by GW()/restoreW() just to keep the
  // week state in sync, and must not silently override whatever screen
  // (e.g. the new Home dashboard) is actually being shown right now.
  var trainEl=document.getElementById('TRAIN');
  if(!trainEl || getComputedStyle(trainEl).display==='none') return;
  var ids=['TRAIN','PROG','NUTR','ACT','SET'];
  ids.forEach(function(id){
    var el=document.getElementById(id);
    if(el) el.style.display=(id==='TRAIN'?'block':'none');
  });
}

function restoreW(w){
  var s=ws(w);
  Object.keys(s.wo).forEach(function(i){
    if(s.wo[i]){var e=document.getElementById('ck'+w+'_'+i);if(e){e.className='wo-chk on';e.textContent='v';}}
  });
  Object.keys(s.nu).forEach(function(i){
    if(s.nu[i]){var e=document.getElementById('nc'+w+'_'+i);if(e){e.className='nt-chk on';e.textContent='v';}}
  });
  var ci=s.ci||{};
  if(ci.weight){var e=document.getElementById('cw'+w);if(e)e.value=ci.weight;}
  if(ci.rhr){var e=document.getElementById('cr'+w);if(e)e.value=ci.rhr;}
  if(ci.energy){var e=document.getElementById('ce'+w);if(e)e.value=ci.energy;}
  if(ci.sleep){var e=document.getElementById('cs'+w);if(e)e.value=ci.sleep;}
  if(ci.notes){var e=document.getElementById('cn'+w);if(e)e.value=ci.notes;}
  Object.keys(s.fi).forEach(function(i){
    var fi=s.fi[i];
    if(fi.a){var e=document.getElementById('af'+w+'_'+i);if(e)e.value=fi.a;}
    if(fi.r){var e=document.getElementById('rf'+w+'_'+i);if(e)e.value=fi.r;}
  });
  Object.keys(s.swaps||{}).forEach(function(i){
    if(!s.swaps[i]) return; // skip empty/null swaps
    var e=document.getElementById('ws'+w+'_'+i);
    if(e){e.textContent=s.swaps[i];e.style.color='var(--blue)';}
    // Restore log button for strength swaps
    applySwapLogBtn(w,parseInt(i),s.swaps[i]);
  });
}

function applySwapLogBtn(w,idx,val){
  if(!val) return;
  var vl=val.toLowerCase();
  if(vl.indexOf('strength')<0&&vl.indexOf('full body')<0&&vl.indexOf('core only')<0&&vl.indexOf('yoga')<0&&vl.indexOf('mobility')<0) return;
  var card=document.getElementById('wc'+w+'_'+idx);
  if(!card) return;
  var btnArea=card.querySelector('.swap-log-area');
  if(!btnArea){
    btnArea=document.createElement('div');
    btnArea.className='swap-log-area';
    btnArea.style.cssText='margin-top:6px';
    var womain=card.querySelector('.wo-main');
    if(womain) womain.appendChild(btnArea);
  }
  btnArea.innerHTML='';
  if(vl.indexOf('strength a')>=0||vl.indexOf('full body a')>=0){
    var lb=document.createElement('button');lb.className='str-btn';
    lb.textContent='Log Full Body A';
    (function(ww){lb.onclick=function(){openStr('A',ww);};})(w);
    btnArea.appendChild(lb);
  } else if(vl.indexOf('strength b')>=0||vl.indexOf('full body b')>=0){
    var lb=document.createElement('button');lb.className='str-btn';
    lb.textContent='Log Full Body B';
    (function(ww){lb.onclick=function(){openStr('B',ww);};})(w);
    btnArea.appendChild(lb);
  }
}

function TW(w,i){
  var s=ws(w);s.wo[i]=!s.wo[i];sv();
  var e=document.getElementById('ck'+w+'_'+i);
  if(e){e.className='wo-chk'+(s.wo[i]?' on':'');e.textContent=s.wo[i]?'v':'';}
  updDots();
}

function saveNT(w,idx,field,val){
  var s=ws(w);
  if(!s.nt)s.nt={};
  if(!s.nt[idx])s.nt[idx]={};
  s.nt[idx][field]=val;
  sv();
}

function TN(w,i){
  var s=ws(w);s.nu[i]=!s.nu[i];sv();
  var e=document.getElementById('nc'+w+'_'+i);
  if(e){e.className='nt-chk'+(s.nu[i]?' on':'');e.textContent=s.nu[i]?'v':'';}
}
function SF(w,i,f,v){var s=ws(w);if(!s.fi[i])s.fi[i]={};s.fi[i][f]=v;sv();}
function SC(w,f,v){ws(w).ci[f]=v;sv();}

function openPk(){
  var maxW=Math.max(17,cw+4);
  var grid=document.getElementById('picker-grid');
  if(!grid){ var sheet=document.getElementById('pk-sheet'); grid=document.createElement('div'); grid.id='picker-grid'; grid.className='pk-grid'; sheet.appendChild(grid); }
  var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var html='';
  for(var w=1;w<=maxW;w++){
    var s=ws(w);
    var d=Object.values(s.wo).filter(Boolean).length;
    var hasData=d>0||(s.ci&&(s.ci.weight||s.ci.notes));
    var weekMon=getWeekStartDate(w);
    var weekEnd=new Date(weekMon); weekEnd.setDate(weekEnd.getDate()+6);
    var dateRange=months[weekMon.getMonth()]+' '+weekMon.getDate()+' – '+
      (weekMon.getMonth()!==weekEnd.getMonth()?months[weekEnd.getMonth()]+' ':'')+weekEnd.getDate();
    var isCurrent=w===getCurrentPlanWeek();
    html+='<div style="padding:10px 14px;border-bottom:1px solid var(--b1);cursor:pointer;display:flex;justify-content:space-between;align-items:center;background:'+(w===cw?'rgba(252,76,2,.08)':'')+'" onclick="GW('+w+', true);closePk()">'
      +'<div>'
      +'<span style="font-size:13px;font-weight:700;color:'+(w===cw?'#FC4C02':'var(--t1)')+'">Week '+w+'</span>'
      +(isCurrent?'<span style="margin-left:6px;font-size:10px;background:#FC4C02;color:white;padding:1px 6px;border-radius:8px">NOW</span>':'')
      +'<div style="font-size:11px;color:var(--t3);margin-top:2px">'+dateRange+'</div>'
      +'</div>'
      +(hasData?'<span style="font-size:11px;color:#00C896;font-weight:600">'+d+' done</span>':'')
      +'</div>';
  }
  html+='<div style="padding:10px 14px;cursor:pointer;display:flex;align-items:center;gap:8px;opacity:.6;border-top:1px dashed var(--b2)" onclick="GW('+(maxW+1)+', true);closePk()">'
    +'<span style="font-size:13px;font-weight:700;color:var(--t2)">+ Add Week '+(maxW+1)+'</span></div>';
  grid.innerHTML=html;
  // Add transparent overlay to catch outside taps
  var ol=document.getElementById('pk-overlay');if(ol)ol.remove();
  var ol2=document.createElement('div');ol2.id='pk-overlay';
  ol2.style.cssText='position:fixed;inset:0;z-index:199';
  ol2.onclick=closePk;
  document.body.appendChild(ol2);
  document.getElementById('pk-sheet').classList.add('open');
  document.getElementById('pk-bg').classList.add('open');
  // Scroll to current week
  setTimeout(function(){
    var cur=grid.querySelector('[style*="rgba(252,76,2"]');
    if(cur) cur.scrollIntoView({block:'center'});
  },50);
}

function closePk(){
  var s=document.getElementById('pk-sheet');if(s)s.classList.remove('open');
  var b=document.getElementById('pk-bg');if(b)b.classList.remove('open');
  var ol=document.getElementById('pk-overlay');if(ol)ol.remove();
}

function doSwap(w,idx,btn){
  var old=document.getElementById('swap-overlay');if(old)old.remove();
  // Get session name from element - use data-orig attribute for original name
  var sess=document.getElementById('ws'+w+'_'+idx);
  var sessName=sess?(sess.getAttribute('data-orig')||sess.textContent.trim()):'';
  // Build swap list based on session type - always comprehensive
  var sl=sessName.toLowerCase();
  var opts=[];
  // Cycling options
  var cycling=['Zwift Ride','Outdoor Ride','Zwift Zone 2','Zwift Intervals','Zwift Sweet Spot','Zwift Climb','Zwift Race','Easy Spin 30 min'];
  // Run options  
  var running=['Easy Run','Tempo Run','Fartlek Run','Hill Repeats','400m Repeats x8','800m Repeats x6','Mile Repeats x4','Track Intervals','Treadmill Run','Walk 30 min'];
  // Swim options
  var swimming=['Swim Easy 30 min','Swim Steady 40 min','Swim Intervals','Open Water Swim'];
  // Strength options
  var strength=['Strength A','Strength B','Core Only 20 min','Yoga/Mobility'];
  // Always Rest Day
  var rest=['Race','Rest Day'];

  if(sl.indexOf('strength')>=0||sl.indexOf('full body')>=0){
    opts=cycling.concat(running).concat(swimming).concat(rest);
  } else if(sl.indexOf('zwift')>=0||sl.indexOf('ride')>=0||sl.indexOf('bike')>=0||sl.indexOf('chase')>=0){
    opts=cycling.concat(running).concat(swimming).concat(strength).concat(rest);
  } else if(sl.indexOf('run')>=0||sl.indexOf('jog')>=0){
    // Put cycling first — most common cross-training swap for a run
    opts=cycling.concat(running).concat(swimming).concat(strength).concat(rest);
  } else if(sl.indexOf('swim')>=0){
    opts=swimming.concat(cycling).concat(running).concat(rest);
  } else {
    opts=cycling.concat(running).concat(swimming).concat(strength).concat(rest);
  }
  opts.push('Custom...');

  // Compact dropdown sheet - replaces the old scrolling pill grid (which
  // could fill most of the screen on mobile with ~20 options and buried
  // Cancel at the bottom). A native <select> is far more compact, uses
  // the OS's own picker UI on mobile, and applies the swap immediately
  // on change - no separate Confirm step needed.
  var overlay=document.createElement('div');
  overlay.id='swap-overlay';
  overlay.style.cssText='position:fixed;inset:0;z-index:300;background:rgba(0,0,0,.6);display:flex;align-items:center;justify-content:center;padding:16px';
  overlay.onclick=function(e){ if(e.target===overlay) overlay.remove(); };

  var sheet=document.createElement('div');
  sheet.style.cssText='background:#111;border-radius:16px;padding:18px;width:100%;max-width:340px';

  var headerRow=document.createElement('div');
  headerRow.style.cssText='display:flex;justify-content:space-between;align-items:center;margin-bottom:14px';

  var lbl=document.createElement('span');
  lbl.style.cssText='font-size:14px;font-weight:700;color:#ffffff';
  lbl.textContent='Swap With';
  headerRow.appendChild(lbl);

  var closeBtn=document.createElement('span');
  closeBtn.style.cssText='width:22px;height:22px;border-radius:50%;background:#1a1a1a;display:flex;align-items:center;justify-content:center;color:#999;font-size:13px;cursor:pointer;flex-shrink:0';
  closeBtn.textContent='\u00d7';
  closeBtn.onclick=function(){overlay.remove();};
  headerRow.appendChild(closeBtn);

  sheet.appendChild(headerRow);

  var select=document.createElement('select');
  select.style.cssText='width:100%;background:#1a1a1a;border:1px solid #333;color:#f0f0f0;font-size:14px;font-weight:600;padding:12px 14px;border-radius:8px';

  opts.forEach(function(opt){
    var optEl=document.createElement('option');
    optEl.value=opt;optEl.textContent=opt;
    optEl.style.cssText='color:#f0f0f0;background:#1a1a1a';
    select.appendChild(optEl);
  });
  select.selectedIndex=-1;

  select.addEventListener('change',function(){
    var val=select.value;
    if(val==='Custom...'){
      var custom=prompt('Enter activity name:');
      overlay.remove();
      if(custom&&custom.trim()) applySwap(w,idx,custom.trim());
      return;
    }
    overlay.remove();
    applySwap(w,idx,val);
  });

  sheet.appendChild(select);
  overlay.appendChild(sheet);
  document.body.appendChild(overlay);
}



function rmSwap(w,i){var o=document.getElementById('swap-overlay');if(o)o.remove();}

function applySwap(w,idx,val){
  var s=ws(w);if(!s.swaps)s.swaps={};s.swaps[idx]=val;sv();
  var e=document.getElementById('ws'+w+'_'+idx);
  if(e){e.textContent=val;e.style.color='var(--blue)';}
  var o=document.getElementById('swap-overlay');if(o)o.remove();
  // Update log button based on new session type
  var card=document.getElementById('wc'+w+'_'+idx);
  if(card){
    // Hide the ORIGINAL static log button from the day's pre-swap session
    // (e.g. "Log Full Body A" baked into the static markup) - it belongs
    // to whatever the session used to be, not what it's being swapped to.
    // Both the original and any dynamically-created replacement share the
    // .str-btn class, so target only the one NOT inside .swap-log-area.
    card.querySelectorAll('.str-btn').forEach(function(b){
      if(!b.closest('.swap-log-area')) b.style.display='none';
    });
    var vl=val.toLowerCase();
    // Find existing log button area or create one
    var btnArea=card.querySelector('.swap-log-area');
    if(!btnArea){
      btnArea=document.createElement('div');
      btnArea.className='swap-log-area';
      btnArea.style.cssText='margin-top:6px';
      card.querySelector('.wo-main').appendChild(btnArea);
    }
    btnArea.innerHTML='';
    if(vl.indexOf('strength a')>=0||vl.indexOf('full body a')>=0){
      var lb=document.createElement('button');lb.className='str-btn';
      lb.textContent='Log Full Body A';
      (function(ww,ii){lb.onclick=function(){openStr('A',ww);};})(w,idx);
      btnArea.appendChild(lb);
    } else if(vl.indexOf('strength b')>=0||vl.indexOf('full body b')>=0){
      var lb=document.createElement('button');lb.className='str-btn';
      lb.textContent='Log Full Body B';
      (function(ww,ii){lb.onclick=function(){openStr('B',ww);};})(w,idx);
      btnArea.appendChild(lb);
    } else if(vl.indexOf('core only')>=0||vl.indexOf('yoga')>=0||vl.indexOf('mobility')>=0){
      var lb=document.createElement('button');lb.className='str-btn';
      lb.textContent='Log '+val;
      lb.style.opacity='0.6';
      btnArea.appendChild(lb);
    }
  }
  toast('Swapped to: '+val);
  // For open-ended cycling/ride swaps, clear the planned duration — a
  // "Zwift Ride" or "Easy Spin" has no time target, just get on the bike.
  var openEndedRide=/zwift ride|outdoor ride|easy spin|easy ride|zwift climb|zwift race/i.test(val);
  if(openEndedRide && card){
    var durEl=card.querySelector('.wof-pl');
    if(durEl) durEl.textContent='';
  }
}

function openStr(letter,w){
  curSW=w;
  var exs=letter==='A'?FBA:FBB;
  var modal=document.getElementById('mod-'+letter);
  var s=ws(w);

  var altMap={
    // FBA exercises
    0:['Goblet Squat','Back Squat','Bulgarian Split Squat','Leg Press','Box Squat','Front Squat','Hack Squat','Step-Up (Plyo Box)','Band Squat','Stability Ball Wall Squat'],
    1:['Romanian Deadlift (RDL)','Conventional Deadlift','Single-Leg RDL','Hip Thrust','Good Mornings','Band Pull-Through','Stability Ball Hamstring Curl','Sumo Deadlift'],
    2:['Bench Press','Incline Bench Press','Overhead Press','Dumbbell Press','Band Press','Push-up on Box','Med Ball Chest Pass','Stability Ball Dumbbell Press'],
    3:['Push-up','Deficit Push-up (on Box)','Band Push-up','Med Ball Push-up','Incline Push-up','Decline Push-up (feet on Box)','Dumbbell Floor Press','Landmine Press'],
    4:['Band Row','Dumbbell Row','Pull-up','Face Pull (Band)','Band Pull-Apart','Stability Ball DB Row','Single-Arm Band Row','Inverted Row'],
    5:['Dead Bug','Plank','Ab Wheel Rollout','Pallof Press (Band)','Hollow Body Hold','Bear Crawl Hold','Stability Ball Pike','Band Woodchop'],
    // FBB exercises (same indices, different context)
    6:['Back Squat','Goblet Squat','Bulgarian Split Squat','Box Squat','Front Squat','Step-Up (Plyo Box)','Band Squat','Hack Squat','Leg Press','Lateral Box Jump to Squat'],
    7:['Single-Leg RDL','Romanian Deadlift (RDL)','Hip Thrust','Band Hip Thrust','Stability Ball Hamstring Curl','Single-Leg Hip Thrust','Good Mornings','Nordic Curl'],
    8:['Dumbbell Press','Bench Press','Incline Dumbbell Press','Overhead Press','Band Press','Stability Ball Dumbbell Press','Med Ball Slam to Press'],
    9:['Pull-up / Lat Pulldown','Band Pulldown','Dumbbell Row','Face Pull (Band)','Band Pull-Apart','Inverted Row','Single-Arm Band Row'],
    10:['Dumbbell Row','Band Row','Pull-up','Single-Arm Cable Row','Stability Ball DB Row','Meadows Row','Chest-Supported Row'],
    11:['Plank','Copenhagen Plank','Side Plank','Ab Wheel Rollout','Stability Ball Rollout','Band Pallof Press','Dead Bug','Bear Crawl Hold']
  };
  // Use FBB indices for B
  var altOffset=letter==='B'?6:0;

  // Build modal using DOM - no innerHTML string issues
  modal.innerHTML='';
  var sheet=document.createElement('div');
  sheet.className='modal-sh';

  // Handle bar
  var hdl=document.createElement('div');hdl.className='mhdl';sheet.appendChild(hdl);

  // Header
  var hdr=document.createElement('div');hdr.className='mhdr';
  var htxt=document.createElement('div');
  htxt.innerHTML='<div class="mtit">Full Body '+letter+'</div><div style="font-size:12px;color:var(--t3)">Week '+w+'</div>';
  var clearBtn=document.createElement('button');
  clearBtn.style.cssText='font-size:11px;color:var(--t3);background:var(--s2);border:1px solid var(--b2);border-radius:8px;padding:3px 8px;cursor:pointer;font-family:inherit;margin-left:8px';
  clearBtn.textContent='Clear';
  (function(capL,capW){clearBtn.onclick=function(){clearStrSession(capL,capW);};})(letter,w);
  htxt.appendChild(clearBtn);
  var xbtn=document.createElement('button');
  xbtn.className='mclose';xbtn.textContent='✕';
  xbtn.addEventListener('click',function(){closeStr(letter);});
  hdr.appendChild(htxt);hdr.appendChild(xbtn);
  sheet.appendChild(hdr);

  // Exercise cards
  exs.forEach(function(ex,ei){
    var alts=(altMap[ei+altOffset]||altMap[ei]||[]).filter(function(a){return a!==ex[0];});

    var card=document.createElement('div');card.className='ex-c';

    // Exercise header
    var exhdr=document.createElement('div');exhdr.className='ex-h';
    var exinfo=document.createElement('div');
    var exnm=document.createElement('div');exnm.className='ex-nm';exnm.id='en_'+letter+'_'+ei;exnm.textContent=ex[0];
    var extip=document.createElement('div');extip.className='ex-tip';extip.textContent=ex[3];
    exinfo.appendChild(exnm);exinfo.appendChild(extip);

    // Swap dropdown
    var sel=document.createElement('select');sel.className='ex-sw';
    var defOpt=document.createElement('option');defOpt.value='';defOpt.textContent='Swap exercise';
    sel.appendChild(defOpt);
    alts.forEach(function(a){var o=document.createElement('option');o.value=a;o.textContent=a;sel.appendChild(o);});
    (function(capEi,capSel){
      capSel.addEventListener('change',function(){
        if(capSel.value){swEx(letter,capEi,capSel.value);capSel.value='';}
      });
    })(ei,sel);

    exhdr.appendChild(exinfo);exhdr.appendChild(sel);
    card.appendChild(exhdr);

    // Column headers
    var colhdr=document.createElement('div');colhdr.className='set-hr';
    colhdr.innerHTML='<div class="sn" style="font-size:10px;color:var(--t3)">SET</div>'
      +'<div class="sp" style="font-size:10px;color:var(--t3)">PREV</div>'
      +'<div style="font-size:10px;color:var(--t3);text-align:center">LBS</div>'
      +'<div style="font-size:10px;color:var(--t3);text-align:center">REPS</div>'
      +'<div></div>';
    card.appendChild(colhdr);

    // Set rows
    for(var si=0;si<3;si++){
      var sd=(s.str&&s.str[letter]&&s.str[letter][ei]&&s.str[letter][ei][si])||{};
      var prev=getPrev(letter,w,ei,si);

      var row=document.createElement('div');
      row.className='set-r'+(sd.done?' done':'');
      row.id='sr_'+letter+'_'+ei+'_'+si;

      var snum=document.createElement('div');snum.className='sn';snum.textContent=si+1;
      var sprev=document.createElement('div');sprev.className='sp';
      sprev.style.cssText='color:var(--blue);font-size:11px;font-weight:600';
      sprev.textContent=prev;

      var winp=document.createElement('input');
      winp.type='number';winp.placeholder='lbs';winp.className='si';
      winp.id='sw_'+letter+'_'+ei+'_'+si;
      if(sd.w)winp.value=sd.w;

      var rinp=document.createElement('input');
      rinp.type='number';rinp.placeholder=ex[2];rinp.className='si';
      rinp.id='sr2_'+letter+'_'+ei+'_'+si;
      if(sd.r)rinp.value=sd.r;

      var chk=document.createElement('div');
      chk.className='sc'+(sd.done?' on':'');
      chk.id='sc_'+letter+'_'+ei+'_'+si;
      if(sd.done)chk.textContent='v';
      (function(capL,capEi,capSi,capChk,capRow){
        capChk.addEventListener('click',function(){
          var on=capChk.classList.contains('on');
          if(on){capChk.classList.remove('on');capChk.textContent='';capRow.classList.remove('done');}
          else{capChk.classList.add('on');capChk.textContent='v';capRow.classList.add('done');}
          savStr(capL);
        });
      })(letter,ei,si,chk,row);

      row.appendChild(snum);row.appendChild(sprev);row.appendChild(winp);row.appendChild(rinp);row.appendChild(chk);
      card.appendChild(row);
    }
    sheet.appendChild(card);
  });

  // Finish button
  var finbtn=document.createElement('button');
  finbtn.className='fin-btn';finbtn.textContent='Finish Workout v';
  finbtn.addEventListener('click',function(){finStr(letter);});
  sheet.appendChild(finbtn);

  modal.appendChild(sheet);
  modal.classList.add('open');
  document.body.style.overflow='hidden';
}

function clearStrSession(l,w){
  if(!confirm('Clear all data for this session?')) return;
  var s=ws(w);
  if(s.str&&s.str[l]) delete s.str[l];
  sv();
  closeStr(l);
  setTimeout(function(){ openStr(l,w); }, 100);
  toast('Session cleared');
}

function getPrev(l,w,ei,si){
  for(var pw=w-1;pw>=1;pw--){
    var ps=ws(pw);
    if(ps.str&&ps.str[l]&&ps.str[l][ei]&&ps.str[l][ei][si]&&ps.str[l][ei][si].w)
      return ps.str[l][ei][si].w+'x'+(ps.str[l][ei][si].r||'?');
  }
  var exs=l==='A'?FBA:FBB;
  var exName=exs[ei]?exs[ei][0]:'';
  var bk=l+'_'+exName.replace(/[^a-zA-Z]/g,'');
  if(st.baseline&&st.baseline[bk])return st.baseline[bk]+' lbs';
  return '-';
}

function closeStr(l){document.getElementById('mod-'+l).classList.remove('open');document.body.style.overflow='';}

function togSet(l,ei,si){
  var ce=document.getElementById('sc_'+l+'_'+ei+'_'+si);
  var re=document.getElementById('sr_'+l+'_'+ei+'_'+si);
  if(!ce)return;
  var on=ce.classList.contains('on');
  ce.className='sc'+(on?'':' on');ce.textContent=on?'':'v';
  if(re)re.className='set-r'+(on?'':' done');
  savStr(l);
}



function swEx(l,ei,v){if(!v)return;var e=document.getElementById('en_'+l+'_'+ei);if(e)e.textContent=v;}

function savStr(l){
  var s=ws(curSW);if(!s.str)s.str={};if(!s.str[l])s.str[l]={};
  s.str[l]._date=getTodayKey(); // stamp when saved
  var exs=l==='A'?FBA:FBB;
  for(var ei=0;ei<exs.length;ei++){
    if(!s.str[l][ei])s.str[l][ei]={};
    for(var si=0;si<3;si++){
      var we=document.getElementById('sw_'+l+'_'+ei+'_'+si);
      var re=document.getElementById('sr2_'+l+'_'+ei+'_'+si);
      var ce=document.getElementById('sc_'+l+'_'+ei+'_'+si);
      s.str[l][ei][si]={w:we?we.value:'',r:re?re.value:'',done:ce?ce.classList.contains('on'):false};
    }
  }
  sv();
}

function finStr(l){
  savStr(l);closeStr(l);
  var dm={A:0,B:2},idx=dm[l];
  if(idx!==undefined){
    TW(curSW,idx);
  }
  toast('Workout complete! 💪');
}

