    var gc=isDM?'rgba(255,255,255,0.08)':'rgba(0,0,0,0.08)';
    var tc=isDM?'rgba(255,255,255,0.6)':'rgba(0,0,0,0.5)';
    var base={responsive:true,maintainAspectRatio:false,animation:false,plugins:{legend:{display:false}},scales:{x:{grid:{color:gc},ticks:{color:tc,font:{size:9}}},y:{grid:{color:gc},ticks:{color:tc,font:{size:9}}}}};

    var sc=document.getElementById('prog-sess-chart');
    if(sc) new Chart(sc,{type:'bar',data:{labels:cd.weekLabels,datasets:[{data:cd.weekCounts,backgroundColor:cd.weekCounts.map(function(v,i){return i===cd.weekCounts.length-1?'#185FA5':'rgba(24,95,165,0.4)';}),borderRadius:4}]},options:Object.assign({},base,{scales:{x:{grid:{color:gc},ticks:{color:tc,font:{size:9}}},y:{grid:{color:gc},ticks:{color:tc,font:{size:9}},min:0}}})});

    // Protein chart lives in Nutrition → Progress tab

    var wc=document.getElementById('prog-wt-chart');
    if(wc&&cd.wtData.length) new Chart(wc,{type:'line',data:{labels:cd.wtLabels,datasets:[{data:cd.wtData,borderColor:'#378ADD',backgroundColor:'rgba(55,138,221,0.08)',borderWidth:2,fill:true,tension:0.3,pointRadius:3,pointBackgroundColor:'#378ADD'}]},options:Object.assign({},base,{scales:{x:{grid:{color:gc},ticks:{color:tc,font:{size:9}}},y:{grid:{color:gc},ticks:{color:tc,font:{size:9}},callback:function(v){return v+'lb';}}}})});

    var lc=document.getElementById('prog-lr-chart');
