function normDate(d){
  if(!d) return '';
  var p=d.split('-');
  if(p.length===3) return p[0]+'-'+(p[1].length<2?'0'+p[1]:p[1])+'-'+(p[2].length<2?'0'+p[2]:p[2]);
  return d;
}
function isDesktop(){ return window.innerWidth >= 1024; }
