function dsShowRidesList(){
  var rp3=document.getElementById('ds-right-panel'); if(rp3) rp3.style.display='none';
  var mc = document.getElementById('ds-content');
  if(!mc) return;
  var _byId = {};
  (st.rides||[]).forEach(function(r){
    var key = r.stravaId ? 'sid:'+r.stravaId : 'k:'+(r.date||'')+(r.name||'')+(r.duration||'');
    var existing = _byId[key];
    if(!existing) { _byId[key]=r; return; }
    // Always prefer the version with more GPS points
    var rGps = (r.gpsLats&&r.gpsLats.length)||0;
    var eGps = (existing.gpsLats&&existing.gpsLats.length)||0;
    if(rGps > eGps) _byId[key]=r;
  });
  var rides = Object.values(_byId).sort(function(a,b){
    return normDate(b.date)>normDate(a.date)?1:-1;
  });

  var wrap = document.createElement('div');
  wrap.style.cssText = 'display:flex;flex-direction:column;height:100%;overflow:hidden';

  var titleBar = document.createElement('div');
  titleBar.style.cssText = 'padding:16px 18px 12px;border-bottom:1px solid #1e2130;font-size:18px;font-weight:700;color:#fff;flex-shrink:0';
  titleBar.textContent = 'Activities';
  wrap.appendChild(titleBar);

  var list = document.createElement('div');
  list.style.cssText = 'overflow-y:auto;flex:1';

  if(!rides.length){
    var empty = document.createElement('div');
    empty.style.cssText = 'padding:40px;text-align:center;color:#64748b';
    empty.textContent = 'No activities yet';
    list.appendChild(empty);
  } else {
    rides.slice(0,60).forEach(function(r){
      var idx = (st.rides||[]).indexOf(r);
      var row = document.createElement('div');
      row.style.cssText = 'display:flex;align-items:center;gap:14px;padding:12px 18px;border-bottom:1px solid #1a1f2e;cursor:pointer';
      row.onmouseover = function(){ this.style.background='#1a1f2e'; };
      row.onmouseout = function(){ this.style.background=''; };
      row.onclick = function(){ openRideDetail(idx); };

      var icon = document.createElement('div');
      icon.style.cssText = 'width:38px;height:38px;border-radius:10px;background:#1a1f2e;border:1px solid #252d40;display:flex;align-items:center;justify-content:center;flex-shrink:0';
      icon.innerHTML = '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#FC4C02" stroke-width="2" stroke-linecap="round"><circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/></svg>';
      row.appendChild(icon);

      var info = document.createElement('div');
      info.style.cssText = 'flex:1;min-width:0';
      var name = document.createElement('div');
      name.style.cssText = 'font-size:13px;font-weight:600;color:#e2e8f0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis';
      var _rn=r.name||r.sportType||'Activity'; if(_rn.indexOf(' ACTIVITY')>0&&parseInt(_rn)>0) _rn=r.sportType||r.type||'Ride'; name.textContent=_rn;
      var date = document.createElement('div');
      date.style.cssText = 'font-size:11px;color:#64748b;margin-top:2px';
      date.textContent = r.date||'';
      info.appendChild(name);
      info.appendChild(date);
      row.appendChild(info);

      var stats = document.createElement('div');
      stats.style.cssText = 'display:flex;gap:16px;flex-shrink:0';
      function addStat(val, lbl, color){
        if(!val) return;
        var s = document.createElement('div');
        s.style.cssText = 'text-align:right';
        s.innerHTML = '<div style="font-size:13px;font-weight:600;color:'+color+'">'+val+'</div><div style="font-size:10px;color:#64748b">'+lbl+'</div>';
        stats.appendChild(s);
      }
      addStat(r.distance ? r.distance+' mi' : '', 'Dist', '#e2e8f0');
      addStat(r.duration||'', 'Time', '#e2e8f0');
      addStat(r.avgPower ? r.avgPower+'w' : '', 'Power', '#FC4C02');
      addStat(r.avgHR ? r.avgHR+' bpm' : '', 'HR', '#60a5fa');
      row.appendChild(stats);
      list.appendChild(row);
    });
  }
  wrap.appendChild(list);
  mc.innerHTML = '';
  mc.appendChild(wrap);
}


function dsInitProfile(){
  var name = (st.profile&&st.profile.name) || 'Mikey';
  var wt = st.weight ? st.weight+'lbs' : '';
  var initials = name.split(' ').map(function(w){return w[0];}).join('').slice(0,2).toUpperCase();
  var el = document.getElementById('ds-avatar-initials'); if(el) el.textContent=initials;
  var pn = document.getElementById('ds-profile-name'); if(pn) pn.textContent=name;
  var pw = document.getElementById('ds-profile-wt'); if(pw) pw.textContent=wt;
  var cw = getCurrentPlanWeek ? getCurrentPlanWeek() : 1;
  var pb = document.getElementById('ds-profile-badge'); if(pb) pb.textContent='Week '+cw;
}

function openDesktopRideDetail(idx){
  var rp2=document.getElementById('ds-right-panel'); if(rp2) rp2.style.display='flex';
  var r = st.rides[idx];
  if(!r) return;
  var FTP = parseInt(st.ftp||186);
  var BWT = parseFloat(st.weight||160);
  var wkg = r.avgPower&&BWT ? (r.avgPower/BWT).toFixed(2) : '--';
  var tss = r.tss ? Math.round(r.tss) : '--';
  var dtStr = '';
  if(r.startTime){
    var dt=new Date(r.startTime);
    var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    var hrs12=dt.getHours()%12||12, mins=('0'+dt.getMinutes()).slice(-2), ampm=dt.getHours()>=12?'PM':'AM';
    dtStr=months[dt.getMonth()]+' '+dt.getDate()+', '+dt.getFullYear()+' &middot; '+hrs12+':'+mins+' '+ampm+' &middot; '+(r.sportType||'Road Cycling');
  } else if(r.date){ dtStr=r.date+' &middot; '+(r.sportType||'Road Cycling'); }

  var lats=r.lats||r.gpsLats, lons=r.lons||r.gpsLons;

  var main = document.getElementById('ds-content');
  if(!main) return;

  // Build route SVG path from GPS
  function buildRouteSVG(lats,lons){
    if(!lats||lats.length<2) return '<text x="300" y="110" text-anchor="middle" fill="#64748b" font-size="12">No GPS data</text>';
    var minLat=Math.min.apply(null,lats),maxLat=Math.max.apply(null,lats);
    var minLon=Math.min.apply(null,lons),maxLon=Math.max.apply(null,lons);
    var pad=0.05;
    var latR=maxLat-minLat||0.01, lonR=maxLon-minLon||0.01;
    var W=560,H=180;
    var points=lats.map(function(la,i){
      var x=((lons[i]-minLon)/lonR)*(W*(1-2*pad))+W*pad;
      var y=H-(((la-minLat)/latR)*(H*(1-2*pad))+H*pad);
      return x.toFixed(1)+','+y.toFixed(1);
    }).join(' ');
    return '<polyline points="'+points+'" fill="none" stroke="#FC4C02" stroke-width="3" stroke-linejoin="round" stroke-linecap="round"/>'+
      '<circle cx="'+lats.map(function(la,i){return((lons[i]-minLon)/lonR)*(W*(1-2*pad))+W*pad;})[0].toFixed(1)+'" cy="'+
      (H-(((lats[0]-minLat)/latR)*(H*(1-2*pad))+H*pad)).toFixed(1)+'" r="6" fill="#4ade80" stroke="#fff" stroke-width="2"/>'+
      '<circle cx="'+lats.map(function(la,i){return((lons[i]-minLon)/lonR)*(W*(1-2*pad))+W*pad;})[lats.length-1].toFixed(1)+'" cy="'+
      (H-(((lats[lats.length-1]-minLat)/latR)*(H*(1-2*pad))+H*pad)).toFixed(1)+'" r="5" fill="#FC4C02" stroke="#fff" stroke-width="2"/>'; 
  }

  // Build elevation SVG
  function buildElevSVG(ele){
    if(!ele||ele.length<2) return '';
    var mn=Math.min.apply(null,ele),mx=Math.max.apply(null,ele),rng=mx-mn||1;
    var W=560,H=44;
    var pts=ele.map(function(v,i){
      return ((i/(ele.length-1))*W).toFixed(1)+','+(H-((v-mn)/rng*(H-8)+4)).toFixed(1);
    }).join(' ');
    return '<defs><linearGradient id="dseg" x1="0" x2="0" y1="0" y2="1">'+
      '<stop offset="0%" stop-color="#FC4C02" stop-opacity=".5"/>'+
      '<stop offset="100%" stop-color="#FC4C02" stop-opacity=".05"/></linearGradient></defs>'+
      '<polygon points="0,'+H+' '+pts+' '+W+','+H+'" fill="url(#dseg)"/>'+
      '<polyline points="'+pts+'" fill="none" stroke="#FC4C02" stroke-width="1.5"/>';
  }

  var routeSVG = buildRouteSVG(lats,lons);
  var elevSVG = buildElevSVG(r.chartEle);

  main.innerHTML =
    '<div style="display:flex;flex-direction:column;height:100%;overflow:hidden">'+
    '<div class="ds-mhdr">'+
      '<div>'+
        '<div class="ds-back" onclick="dsNav(&apos;activities&apos;)">&lsaquo; Back</div>'+
        '<div class="ds-title">'+(r.name||'Activity')+'</div>'+
        '<div class="ds-subtitle">'+dtStr+'</div>'+
      '</div>'+
      '<div class="ds-actions">'+
        '<div class="ds-btn"><i class="ti ti-share"></i> Share</div>'+
        '<div class="ds-btn"><i class="ti ti-download"></i> Export</div>'+
        '<div class="ds-btn"><i class="ti ti-dots"></i></div>'+
      '</div>'+
    '</div>'+
    '<div class="ds-stats">'+
      '<div class="ds-stat"><div class="ds-sv">'+(r.duration||'--')+'</div><div class="ds-sl">Time</div></div>'+
      '<div class="ds-stat"><div class="ds-sv">'+(r.distance?r.distance+' mi':'--')+'</div><div class="ds-sl">Distance</div></div>'+
      '<div class="ds-stat"><div class="ds-sv o">'+wkg+' W/kg</div><div class="ds-sl">Intensity</div></div>'+
      '<div class="ds-stat"><div class="ds-sv b">'+(r.avgHR?r.avgHR+' bpm':'--')+'</div><div class="ds-sl">Avg HR</div></div>'+
      '<div class="ds-stat"><div class="ds-sv a">'+tss+' <span style="font-size:11px">TSS</span></div><div class="ds-sl">Training stress</div></div>'+
      '<div class="ds-stat"><div class="ds-sv">'+(r.calories?r.calories+' Cal':'--')+'</div><div class="ds-sl">Calories</div></div>'+
    '</div>'+
    '<div class="ds-tabs"><div class="ds-tab on">Route</div><div class="ds-tab">Charts</div><div class="ds-tab">Laps</div><div class="ds-tab">Breakdown</div></div>'+
    '<div class="ds-scroll">'+
      '<div id="ds-real-map" style="height:210px;flex-shrink:0"></div>'+
      '<div class="ds-elev">'+
        '<div class="ds-elev-lbl">Elevation</div>'+
        '<svg style="width:100%;height:48px" viewBox="0 0 560 48" preserveAspectRatio="none">'+elevSVG+'</svg>'+
      '</div>'+
      '<div class="ds-c3">'+
        '<div class="ds-card">'+
          '<div class="ds-card-hd" style="color:#FC4C02"><i class="ti ti-bolt" style="font-size:11px"></i> POWER</div>'+
          '<div class="ds-card-nums">'+
            '<div><span class="ds-card-main">'+(r.avgPower||'--')+'</span><span class="ds-card-unit">w NP</span></div>'+
            '<div><span class="ds-card-sub">'+(r.maxPower||'--')+'</span><span class="ds-card-sublbl">w Max</span></div>'+
          '</div>'+
          '<svg class="ds-spark" viewBox="0 0 240 34" preserveAspectRatio="none"><path d="M0,28 C20,24 40,18 60,14 C80,10 100,16 120,12 C140,8 160,14 180,10 C200,6 220,12 240,8" fill="none" stroke="#FC4C02" stroke-width="1.5" opacity=".9"/><path d="M0,28 C20,24 40,18 60,14 C80,10 100,16 120,12 C140,8 160,14 180,10 C200,6 220,12 240,8 L240,34 L0,34 Z" fill="#FC4C02" fill-opacity=".1"/></svg>'+
        '</div>'+
        '<div class="ds-card">'+
          '<div class="ds-card-hd" style="color:#e24b4a"><i class="ti ti-heart" style="font-size:11px"></i> HEART RATE</div>'+
          '<div class="ds-card-nums">'+
            '<div><span class="ds-card-main" style="color:#60a5fa">'+(r.avgHR||'--')+'</span><span class="ds-card-unit">bpm Avg</span></div>'+
            '<div><span class="ds-card-sub">'+(r.maxHR||'--')+'</span><span class="ds-card-sublbl">Max</span></div>'+
          '</div>'+
          '<svg class="ds-spark" viewBox="0 0 240 34" preserveAspectRatio="none"><path d="M0,24 C20,20 40,16 60,18 C80,20 100,12 120,8 C140,4 160,12 180,8 C200,4 220,10 240,12" fill="none" stroke="#e24b4a" stroke-width="1.5" opacity=".9"/><path d="M0,24 C20,20 40,16 60,18 C80,20 100,12 120,8 C140,4 160,12 180,8 C200,4 220,10 240,12 L240,34 L0,34 Z" fill="#e24b4a" fill-opacity=".1"/></svg>'+
        '</div>'+
        '<div class="ds-card">'+
          '<div class="ds-card-hd" style="color:#a78bfa"><i class="ti ti-rotate-clockwise" style="font-size:11px"></i> CADENCE</div>'+
          '<div class="ds-card-nums">'+
            '<div><span class="ds-card-main">'+(r.avgCadence||'--')+'</span><span class="ds-card-unit">rpm Avg</span></div>'+
            '<div><span class="ds-card-sub">'+(r.maxCadence||'--')+'</span><span class="ds-card-sublbl">Max</span></div>'+
          '</div>'+
          '<svg class="ds-spark" viewBox="0 0 240 34" preserveAspectRatio="none"><path d="M0,18 C20,16 40,20 60,14 C80,8 100,14 120,16 C140,18 160,12 180,10 C200,8 220,12 240,14" fill="none" stroke="#a78bfa" stroke-width="1.5" opacity=".9"/><path d="M0,18 C20,16 40,20 60,14 C80,8 100,14 120,16 C140,18 160,12 180,10 C200,8 220,12 240,14 L240,34 L0,34 Z" fill="#a78bfa" fill-opacity=".1"/></svg>'+
        '</div>'+
      '</div>'+
      '<div class="ds-c4">'+
        '<div class="ds-c4card"><div class="ds-c4hd"><i class="ti ti-gauge" style="font-size:11px"></i> SPEED</div><div class="ds-c4main">'+(r.avgSpeed?Math.round(r.avgSpeed*10)/10+' mph':'--')+'</div><div class="ds-c4sub">'+(r.maxSpeed?r.maxSpeed+' max':'')+'</div></div>'+
        '<div class="ds-c4card"><div class="ds-c4hd"><i class="ti ti-mountain" style="font-size:11px"></i> ELEVATION</div><div class="ds-c4main">'+(r.elevation?r.elevation+' ft':'--')+'</div><div class="ds-c4sub">gain</div></div>'+
        '<div class="ds-c4card"><div class="ds-c4hd"><i class="ti ti-temperature" style="font-size:11px"></i> TEMPERATURE</div><div class="ds-c4main">'+(r.avgTemp?r.avgTemp+'°F':'--')+'</div><div class="ds-c4sub">'+(r.maxTemp?r.maxTemp+'° max':'')+'</div></div>'+
        '<div class="ds-c4card"><div class="ds-c4hd"><i class="ti ti-wind" style="font-size:11px"></i> WIND</div><div class="ds-c4main">--</div><div class="ds-c4sub">from conditions</div></div>'+
      '</div>'+
    '</div>'+
  '</div>';

  // Init real Leaflet map - find div and inject buildRouteMap HTML
  (function initDsMap(){
    var mapDiv = document.getElementById('ds-real-map');
    if(!mapDiv){ setTimeout(initDsMap, 100); return; }
    var gpsLats = lats && lats.length > 1 ? lats : null;
    var gpsLons = lons && lons.length > 1 ? lons : null;
    if(!gpsLats && r.stravaId){
      var alt=(st.rides||[]).find(function(x){return x.stravaId===r.stravaId&&x.gpsLats&&x.gpsLats.length>1;});
      if(alt){gpsLats=alt.gpsLats;gpsLons=alt.gpsLons;}
    }
    if(gpsLats && gpsLats.length > 1){
      mapDiv.innerHTML = buildRouteMap(gpsLats, gpsLons, r.chartPwr||[], FTP);
    } else {
      mapDiv.style.cssText='height:210px;background:#1c2535;display:flex;align-items:center;justify-content:center;color:#64748b;font-size:13px;flex-shrink:0';
      mapDiv.textContent='No GPS data';
    }
    var bb=document.getElementById('ds-back-btn');
    if(bb) bb.onclick=function(){ dsNav('activities'); };
  })();

  // Right panel
  var rp = document.getElementById('ds-right-panel');
  if(rp){
    // Fetch weather for right panel
    var lat = lats&&lats[0] ? lats[0] : 42.9634;
    var lon = lons&&lons[0] ? lons[0] : -85.6681;
    rp.innerHTML =
      '<div class="ds-rp">'+
        '<div class="ds-rp-hd"><div class="ds-rp-t">Conditions</div><div class="ds-rp-link">View details &rsaquo;</div></div>'+
        '<div class="ds-conds" id="ds-conds-grid">'+
          '<div style="text-align:center"><i class="ti ti-temperature" style="font-size:22px;color:#94a3b8;display:block;margin-bottom:4px"></i><div class="ds-cd-val" id="ds-cond-temp">--</div><div class="ds-cd-lbl">Temp</div></div>'+
          '<div style="text-align:center"><i class="ti ti-wind" style="font-size:22px;color:#94a3b8;display:block;margin-bottom:4px"></i><div class="ds-cd-val" id="ds-cond-wind">--</div><div class="ds-cd-lbl">Wind</div></div>'+
          '<div style="text-align:center"><i class="ti ti-droplet" style="font-size:22px;color:#94a3b8;display:block;margin-bottom:4px"></i><div class="ds-cd-val" id="ds-cond-hum">--</div><div class="ds-cd-lbl">Humidity</div></div>'+
          '<div style="text-align:center"><i class="ti ti-eye" style="font-size:22px;color:#94a3b8;display:block;margin-bottom:4px"></i><div class="ds-cd-val">10 mi</div><div class="ds-cd-lbl">Visibility</div></div>'+
        '</div>'+
      '</div>'+
      '<div class="ds-rp">'+
        '<div class="ds-rp-t">AI Ride Summary</div>'+
        '<div class="ds-ai-wrap">'+
          '<div><div class="ds-ai-label">Great Ride! 🎉</div><div class="ds-ai-body">Strong aerobic effort with good pacing and consistent power.</div></div>'+
          '<svg width="68" height="68" viewBox="0 0 68 68" style="flex-shrink:0">'+
            '<circle cx="34" cy="34" r="26" fill="none" stroke="#1e2130" stroke-width="5"/>'+
            '<circle cx="34" cy="34" r="26" fill="none" stroke="#4ade80" stroke-width="5" stroke-dasharray="138 163" stroke-dashoffset="39" stroke-linecap="round" transform="rotate(-90 34 34)"/>'+
            '<text x="34" y="31" text-anchor="middle" font-size="16" font-weight="700" fill="#fff">'+(r.rideScore||84)+'</text>'+
            '<text x="34" y="42" text-anchor="middle" font-size="7" fill="#64748b" letter-spacing="0.8">RIDE SCORE</text>'+
          '</svg>'+
        '</div>'+
        '<div class="ds-view-full">View Full Analysis</div>'+
      '</div>'+
      '<div class="ds-rp">'+
        '<div class="ds-rp-t">Key Insights</div>'+
        '<div class="ds-ins-list">'+
          '<div class="ds-ins"><i class="ti ti-bolt" style="color:#FC4C02"></i>Held steady power with consistent pacing throughout.</div>'+
          '<div class="ds-ins"><i class="ti ti-mountain" style="color:#f59e0b"></i>Strong climbing — best 20-min power on elevation.</div>'+
          '<div class="ds-ins"><i class="ti ti-heart" style="color:#e24b4a"></i>HR drift minimal. Excellent aerobic conditioning.</div>'+
          '<div class="ds-ins"><i class="ti ti-droplet" style="color:#60a5fa"></i>Hydration was on point. Keep it up!</div>'+
        '</div>'+
      '</div>'+
      '<div class="ds-rp">'+
        '<div class="ds-rp-hd"><div class="ds-rp-t">Laps</div><div class="ds-rp-link">View all &rsaquo;</div></div>'+
        '<table class="ds-laps"><tr><th>Lap</th><th>Dist</th><th>Time</th><th>Pwr</th><th>HR</th></tr></table>'+
        '<div id="ds-laps-body"></div>'+
      '</div>';

    // Populate laps if available
    if(r.laps&&r.laps.length){
      var lbody = document.getElementById('ds-laps-body');
      if(lbody){
        var lt='<table class="ds-laps">';
        r.laps.slice(0,8).forEach(function(lap,i){
          lt+='<tr><td>'+(i+1)+'</td><td>'+(lap.distance?lap.distance.toFixed(1)+' mi':'--')+'</td><td>'+(lap.time||'--')+'</td><td>'+(lap.avgPower?lap.avgPower+'w':'--')+'</td><td>'+(lap.avgHR?lap.avgHR:'--')+'</td></tr>';
        });
        lt+='</table>';
        lbody.innerHTML=lt;
      }
    }

    // Fetch current conditions
    fetch('https://api.open-meteo.com/v1/forecast?latitude='+lat+'&longitude='+lon+'&current=temperature_2m,windspeed_10m,relativehumidity_2m,winddirection_10m&temperature_unit=fahrenheit&windspeed_unit=mph&timezone=America%2FChicago')
      .then(function(res){return res.json();})
      .then(function(wx){
        if(wx&&wx.current){
          var c=wx.current;
          var dirs=['N','NE','E','SE','S','SW','W','NW'];
          var wdir=dirs[Math.round((c.winddirection_10m||0)/45)%8];
          var tmp=document.getElementById('ds-cond-temp'); if(tmp) tmp.textContent=Math.round(c.temperature_2m)+'°F';
          var wnd=document.getElementById('ds-cond-wind'); if(wnd) wnd.textContent=wdir+' '+Math.round(c.windspeed_10m);
          var hum=document.getElementById('ds-cond-hum'); if(hum) hum.textContent=Math.round(c.relativehumidity_2m)+'%';
        }
      }).catch(function(){});
  }
}

// Intercept openRideDetail on desktop
var _origOpenRideDetail = null;
window.addEventListener('load', function(){
  dsInitProfile();
  if(isDesktop()){
    dsInitProfile();
    dsNav('dashboard');
    // Backup in case st.rides wasn't ready yet
    setTimeout(function(){ if(isDesktop()){ dsInitProfile(); dsNav('dashboard'); } }, 2000);
  }
  _origOpenRideDetail = openRideDetail;
  openRideDetail = function(idx){
    if(isDesktop()){
      // Highlight nav
      document.querySelectorAll('.ds-ni').forEach(function(n){n.classList.remove('on');});
      var act=document.getElementById('ds-ni-activities'); if(act) act.classList.add('on');
      openDesktopRideDetail(idx);
    } else {
      _origOpenRideDetail(idx);
    }
  };
});
// ─────────────────────────────────────────────────────────────────────────────

function openRideDetail(idx){
  var r = st.rides[idx];
  if(!r) return;
  var old = document.getElementById('ride-detail-modal');
  if(old) old.remove();

  var FTP = parseInt(st.ftp||186);
  var BWT = parseFloat(st.weight||160);

  var overlay = document.createElement('div');
  overlay.id = 'ride-detail-modal';
  overlay.style.cssText = 'position:fixed;inset:0;bottom:60px;z-index:200;background:var(--bg);display:flex;flex-direction:column;overflow:hidden;max-width:480px;margin:0 auto;left:50%;transform:translateX(-50%);right:auto;width:100%;box-shadow:0 0 40px rgba(0,0,0,.25)';

  // Header - Apple Health style: back chevron on its own row, large bold
  // title below it, subtitle below that. No filled header bar background.
  var hdr = document.createElement('div');
  hdr.style.cssText = 'padding:8px 16px 16px;flex-shrink:0';

  var dtStr = '';
  if(r.startTime){
    var dt = new Date(r.startTime);
    var days=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    var hrs12 = dt.getHours()%12||12;
    var mins = ('0'+dt.getMinutes()).slice(-2);
    var ampm = dt.getHours()>=12?'PM':'AM';
    dtStr = days[dt.getDay()]+', '+months[dt.getMonth()]+' '+dt.getDate()+' &middot; '+hrs12+':'+mins+' '+ampm;
  } else if(r.date){
    dtStr = r.date;
  }

  var topRow=document.createElement('div');
  topRow.style.cssText='display:flex;align-items:center;justify-content:space-between;margin-bottom:10px';
  var backBtn=document.createElement('button');
  backBtn.innerHTML='<svg width="11" height="18" viewBox="0 0 12 20" fill="none" stroke="#FC4C02" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><path d="M10 2 2 10l8 8"/></svg>';
  backBtn.style.cssText='background:none;border:none;cursor:pointer;padding:0;display:flex;align-items:center';
  backBtn.onclick=function(){ closeRideDetail(); };
  var moreBtn=document.createElement('button');
  moreBtn.innerHTML='<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--t1)" stroke-width="2.2" stroke-linecap="round"><circle cx="12" cy="5" r="1"/><circle cx="12" cy="12" r="1"/><circle cx="12" cy="19" r="1"/></svg>';
  moreBtn.style.cssText='background:none;border:none;cursor:pointer;padding:6px;display:flex;align-items:center';
  moreBtn.onclick=function(){ openRideDetailMoreMenu(idx); };
  topRow.appendChild(backBtn);
  topRow.appendChild(moreBtn);

  var titleWrap=document.createElement('div');
  titleWrap.innerHTML='<div id="ride-detail-name" style="font-size:19px;font-weight:600;color:var(--t1)">'+(r.name||'Activity')+'</div>'
    +'<div style="font-size:13px;color:var(--t3);margin-top:2px">'+dtStr+'</div>';

  hdr.appendChild(topRow);
  hdr.appendChild(titleWrap);

  // Hero stat row - generous 2x3 grid (matching the reference's Time/
  // Distance/Intensity/HR/Power/TSS layout) plus a full-width Calories
  // row, instead of a cramped single 4-cell strip.
  var rwkg = r.np&&BWT?(r.np/BWT*2.20462).toFixed(2):r.avgPwr?(r.avgPwr/BWT*2.20462).toFixed(2):null;
  var heroRow=document.createElement('div');
  heroRow.style.cssText='padding:0 16px;flex-shrink:0';
  var heroGrid=document.createElement('div');
  heroGrid.style.cssText='display:grid;grid-template-columns:1fr 1fr;gap:20px 24px';
  // Restrained palette: everything neutral except intensity (the one
  // number that actually signals effort), avoiding the "three colors
  // firing at once" look. Lighter weight and looser letter-spacing,
  // matching real Apple Health's quieter, more spacious feel.
  [
    {v:r.duration||'-',l:'Time'},
    {v:(r.distance||'-')+(r.distance?' mi':''),l:'Distance'},
    {v:rwkg?rwkg+' W/kg':'-',l:'Intensity',c:'var(--orange)'},
    {v:r.avgHR?r.avgHR+' bpm':'-',l:'Avg HR'},
    {v:(r.avgPwr||'-')+(r.avgPwr?' w':''),l:'Avg Power'},
    {v:r.tss||'-',l:'Training Stress'}
  ].forEach(function(s){
    var cell=document.createElement('div');
    cell.innerHTML='<div style="font-size:19px;font-weight:500;color:'+(s.c||'var(--t1)')+';line-height:1.2">'+s.v+'</div>'
      +'<div style="font-size:11px;font-weight:500;color:var(--t3);margin-top:3px">'+s.l+'</div>';
    heroGrid.appendChild(cell);
  });
  heroRow.appendChild(heroGrid);
  if(r.calories){
    var calRow=document.createElement('div');
    calRow.style.cssText='margin-top:20px';
    calRow.innerHTML='<div style="font-size:19px;font-weight:500;color:var(--t1)">'+r.calories+' Cal</div>'
      +'<div style="font-size:11px;font-weight:500;color:var(--t3);margin-top:3px">Calories</div>';
    heroRow.appendChild(calRow);
  }
  var heroSpacer=document.createElement('div');
  heroSpacer.style.cssText='height:20px';
  heroRow.appendChild(heroSpacer);


  // Tab bar - exact match to the reference: Overview/Map/Charts/Laps/More,
  // plain underline style (bold + orange underline on active, plain gray
  // text otherwise), not filled pills. Map/Charts route to the existing
  // Route/Performance tab content under the hood; Weather/Equipment/AI
  // Analysis live behind "More" since the reference itself only shows
  // 5 tabs and doesn't have those three sections at all.
  var tabDefs=[
    {id:'overview',label:'Overview'},
    {id:'map',label:'Map'},
    {id:'charts',label:'Charts'},
    {id:'laps',label:'Laps'},
    {id:'weather',label:'Weather'},
    {id:'equipment',label:'Equipment'},
    {id:'analysis',label:'AI Analysis'}
  ];
  var activeTab='overview';
  var tabsRow=document.createElement('div');
  tabsRow.className='aiq-hscroll';
  tabsRow.style.cssText='display:flex;gap:18px;overflow-x:auto;padding:8px 16px 0;-webkit-overflow-scrolling:touch;flex-shrink:0;border-bottom:1px solid var(--b1)';
  var tabBtns={};
  tabDefs.forEach(function(t){
    var btn=document.createElement('button');
    btn.textContent=t.label;
    btn.style.cssText='flex-shrink:0;padding:0 0 10px;background:none;border:none;border-bottom:2px solid transparent;font-size:14px;cursor:pointer;white-space:nowrap';
    btn.onclick=function(){
      activeTab=t.id; renderTabs();
    };
    tabBtns[t.id]=btn;
    tabsRow.appendChild(btn);
  });

  var body = document.createElement('div');
  body.id = 'ride-detail-body';
  body.className = 'aiq-vscroll';
  body.style.cssText = 'flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch;padding-bottom:80px';
  document.body.style.overflow = 'hidden';

  overlay.appendChild(hdr);
  overlay.appendChild(heroRow);
  overlay.appendChild(tabsRow);
  overlay.appendChild(body);
  document.body.appendChild(overlay);

  function updateTabStyles(){
    tabDefs.forEach(function(t){
      var active=t.id===activeTab;
      tabBtns[t.id].style.fontWeight=active?'700':'400';
      tabBtns[t.id].style.color=active?'var(--t1)':'var(--t3)';
      tabBtns[t.id].style.borderBottomColor=active?'#FC4C02':'transparent';
    });
  }

  function renderTabs(){
    updateTabStyles();
    body.innerHTML='';
    if(activeTab==='overview') renderRideOverviewTab(body, r, idx, FTP, BWT);
    else if(activeTab==='map') renderRideRouteTab(body, r, idx, FTP, BWT);
    else if(activeTab==='charts') renderRidePerformanceTab(body, r, idx, FTP, BWT);
    else if(activeTab==='laps') renderRideLapsTab(body, r, idx);
    else if(activeTab==='weather') renderRideWeatherTab(body, r, idx);
    else if(activeTab==='equipment') renderRideEquipmentTab(body, r, idx);
    else if(activeTab==='analysis') renderRideAnalysisTab(body, r, idx, FTP, BWT);
  }

  renderTabs();
}

// -- LAPS TAB: genuinely blocked on real data - lap records are not
// currently parsed/stored anywhere in this app (confirmed earlier this
// session). Shown honestly as not-yet-available rather than faked.
function renderRideLapsTab(body, r, idx){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:40px 20px;text-align:center;color:var(--t3)';
  wrap.innerHTML='<div style="font-size:14px;font-weight:600;color:var(--t1);margin-bottom:8px">Lap data not available yet</div>'
    +'<div style="font-size:13px;line-height:1.5">This ride was not recorded with lap markers, or lap data has not been imported for it.</div>';
  body.appendChild(wrap);
}

// -- OVERVIEW TAB: AI Coach insight card + compact route preview + key stats

// Achievement strip for a ride's Overview: surfaces genuine bests computed
// against the rider's own history. Only shows a badge when this ride actually
// holds the all-time max for that metric (or ties it), so nothing here is
// decorative or invented. If nothing qualifies, the strip is omitted entirely.
function renderAchievementStrip(wrap, r, idx){
  var rides=(st.rides||[]).filter(function(x){ return !x.deleted; });
  if(rides.length<2) return; // need history to compare against

  var badges=[];

  // Helper: is this ride's value the strict max (or tie for max) across all rides?
  function isBestBy(getter){
    var mine=getter(r);
    if(mine==null || !(mine>0)) return false;
    var max=0;
    rides.forEach(function(x){ var v=getter(x); if(v!=null && v>max) max=v; });
    return mine>=max && max>0;
  }

  if(isBestBy(function(x){return x.distance;})){
    badges.push({icon:'route', label:'Longest ride', val:r.distance+' mi'});
  }
  if(isBestBy(function(x){return x.elev;})){
    badges.push({icon:'mountain', label:'Most climbing', val:r.elev+' ft'});
  }
  if(isBestBy(function(x){return x.tss;})){
    badges.push({icon:'flame', label:'Highest TSS', val:''+r.tss});
  }
  if(isBestBy(function(x){return (x.peak20 || (x.powerCurve && x.powerCurve[1200])) || null;})){
    var p20=r.peak20 || (r.powerCurve && r.powerCurve[1200]);
    if(p20) badges.push({icon:'bolt', label:'Best 20-min power', val:p20+' W'});
  }
  if(isBestBy(function(x){return x.np;})){
    badges.push({icon:'bolt', label:'Highest NP', val:r.np+' W'});
  }

  if(!badges.length) return;

  function ico(name){
    var o='<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#E8B22E" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">';
    if(name==='route') return o+'<circle cx="6" cy="19" r="3"/><path d="M9 19h8.5a3.5 3.5 0 0 0 0-7h-11a3.5 3.5 0 0 1 0-7H15"/><circle cx="18" cy="5" r="3"/></svg>';
    if(name==='mountain') return o+'<path d="m8 3 4 8 5-5 5 15H2L8 3z"/></svg>';
    if(name==='flame') return o+'<path d="M8.5 14.5A2.5 2.5 0 0 0 11 12c0-1.38-.5-2-1-3-1.072-2.143-.224-4.054 2-6 .5 2.5 2 4.9 4 6.5 2 1.6 3 3.5 3 5.5a7 7 0 1 1-14 0c0-1.153.433-2.294 1-3a2.5 2.5 0 0 0 2.5 2.5z"/></svg>';
    // bolt
    return o+'<path d="M13 2 3 14h9l-1 8 10-12h-9l1-8z"/></svg>';
  }

  var card=document.createElement('div');
  card.style.cssText='margin:4px 0 14px;background:var(--s2);border:1px solid var(--b1);border-radius:14px;padding:14px';
  var head=document.createElement('div');
  head.style.cssText='font-size:11px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.06em;margin-bottom:12px;display:flex;align-items:center;gap:6px';
  head.innerHTML='<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#E8B22E" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="8" r="6"/><path d="M15.477 12.89 17 22l-5-3-5 3 1.523-9.11"/></svg>Achievements';
  card.appendChild(head);

  var strip=document.createElement('div');
  strip.className='aiq-hscroll';
  strip.style.cssText='display:flex;gap:10px;overflow-x:auto;-webkit-overflow-scrolling:touch;padding-bottom:4px';
  badges.forEach(function(b){
    var chip=document.createElement('div');
    chip.style.cssText='flex:0 0 auto;background:rgba(232,178,46,.10);border:1px solid rgba(232,178,46,.30);border-radius:12px;padding:10px 12px;min-width:120px';
    chip.innerHTML='<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">'+ico(b.icon)
      +'<span style="font-size:11px;font-weight:700;color:#E8B22E">'+b.label+'</span></div>'
      +'<div style="font-size:17px;font-weight:800;color:var(--t1)">'+b.val+'</div>';
    strip.appendChild(chip);
  });
  card.appendChild(strip);

  // Equipment used line (real, from the resolved gear) — small footer tie-in.
  var gearName = r.gearName || (r.gearId && st.stravaGearMap && st.stravaGearMap[r.gearId]) || null;
  if(gearName){
    var foot=document.createElement('div');
    foot.style.cssText='font-size:11px;color:var(--t3);margin-top:10px';
    foot.textContent='Equipment: '+gearName;
    card.appendChild(foot);
  }

  wrap.appendChild(card);
}

function renderRideOverviewTab(body, r, idx, FTP, BWT){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:16px';

  // AI Coach Insight - flat, no card background, matching the reference
  // exactly: lightning icon + label + Beta pill, green bold headline,
  // icon+text rows, RECOMMENDATION caps label, Ask Coach outline button.
  var coachSection=document.createElement('div');
  coachSection.id='ride-coach-card';
  coachSection.style.cssText='margin-bottom:24px';
  coachSection.innerHTML='<div style="display:flex;align-items:center;gap:6px;margin-bottom:14px">'
    +'<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--t3)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M13 2 3 14h9l-1 8 10-12h-9l1-8z"/></svg>'
    +'<span style="font-size:12px;color:var(--t3);font-weight:600;text-transform:uppercase;letter-spacing:.04em">AI Coach Insight</span>'
    +'<span style="font-size:9px;font-weight:600;color:var(--t3);border:1px solid var(--b1);padding:2px 6px;border-radius:6px">Beta</span></div>'
    +'<div id="ride-coach-body" style="font-size:14px;color:var(--t2);line-height:1.6">Analyzing this ride&hellip;</div>';
  wrap.appendChild(coachSection);

  // Route map preview - if GPS available, shown here on Overview like the
  // reference (full map tools live on the Route tab)
  var _gpsR = r;
  if(!(r.gpsLats&&r.gpsLats.length>5) && r.stravaId){
    var _alt2=(st.rides||[]).find(function(x){return x.stravaId===r.stravaId&&x.gpsLats&&x.gpsLats.length>5;});
    if(_alt2) _gpsR=_alt2;
  }
  if(_gpsR.gpsLats && _gpsR.gpsLats.length>5){
    var mapWrap=document.createElement('div');
    mapWrap.style.cssText='position:relative;border-radius:16px;overflow:hidden;margin-bottom:14px';
    mapWrap.innerHTML=buildRouteMap(_gpsR.lats||_gpsR.gpsLats, _gpsR.lons||_gpsR.gpsLons, r.chartPwr||[], FTP);
    var previewMapId = window._lastRouteMapId;
    var mapTools=document.createElement('div');
    mapTools.style.cssText='position:absolute;top:10px;right:10px;z-index:400;display:flex;flex-direction:column;gap:6px';
    var layersBtn=document.createElement('div');
    layersBtn.style.cssText='background:rgba(20,20,22,.85);border-radius:8px;width:32px;height:32px;display:flex;align-items:center;justify-content:center;cursor:pointer';
    layersBtn.title='Toggle satellite';
    layersBtn.innerHTML='<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2"><polygon points="12 2 2 7 12 12 22 7 12 2"/><polyline points="2 17 12 22 22 17"/><polyline points="2 12 12 17 22 12"/></svg>';
    layersBtn.onclick=function(){
      var h=window['_routeMap_'+previewMapId];
      if(!h || !h.map) return;
      if(h.satOn){
        if(h.sat){ try{h.map.removeLayer(h.sat);}catch(e){} }
        try{h.base.addTo(h.map);}catch(e){}
        h.satOn=false;
      } else {
        if(!h.sat){
          h.sat=L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',{maxZoom:18,attribution:'Esri'});
        }
        try{h.base.remove();}catch(e){}
        try{h.sat.addTo(h.map);}catch(e){}
        h.satOn=true;
      }
    };
    var expandBtn=document.createElement('div');
    expandBtn.style.cssText='background:rgba(20,20,22,.85);border-radius:8px;width:32px;height:32px;display:flex;align-items:center;justify-content:center;cursor:pointer';
    expandBtn.title='Open full map';
    expandBtn.innerHTML='<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2"><path d="M15 3h6v6M9 21H3v-6M21 3l-7 7M3 21l7-7"/></svg>';
    expandBtn.onclick=function(){
      var lats=r.lats||r.gpsLats, lons=r.lons||r.gpsLons;
      if(!lats || lats.length<2) return;
      var ov=document.createElement('div');
      ov.id='ride-map-fullscreen';
      ov.style.cssText='position:fixed;inset:0;z-index:9000;background:var(--bg);display:flex;flex-direction:column';
      var fsMapId='ride-fs-map-'+Date.now();
      ov.innerHTML='<div style="flex:1;position:relative"><div id="'+fsMapId+'" style="position:absolute;inset:0"></div>'
        +'<button id="ride-fs-close" style="position:absolute;top:calc(12px + env(safe-area-inset-top));right:12px;z-index:50;width:40px;height:40px;border-radius:50%;background:rgba(20,20,22,.9);border:1px solid rgba(255,255,255,.2);color:#fff;font-size:22px;line-height:1;cursor:pointer;display:flex;align-items:center;justify-content:center">&times;</button></div>';
      document.body.appendChild(ov);
      document.getElementById('ride-fs-close').onclick=function(){ ov.remove(); };
      setTimeout(function(){
        if(typeof L==='undefined') return;
        var m=L.map(fsMapId,{zoomControl:true,scrollWheelZoom:true});
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:18}).addTo(m);
        var pts=lats.map(function(la,i){return[la,lons[i]];});
        L.polyline(pts,{color:'#FC4C02',weight:4,opacity:.9}).addTo(m);
        L.circleMarker(pts[0],{radius:7,fillColor:'#1D9E75',color:'#fff',weight:2,fillOpacity:1}).addTo(m);
        L.circleMarker(pts[pts.length-1],{radius:7,fillColor:'#FC4C02',color:'#fff',weight:2,fillOpacity:1}).addTo(m);
        m.fitBounds(L.latLngBounds(pts),{padding:[40,40]});
        setTimeout(function(){ try{m.invalidateSize();}catch(e){} },250);
      },80);
    };
    mapTools.appendChild(layersBtn);
    mapTools.appendChild(expandBtn);
    mapWrap.appendChild(mapTools);
    wrap.appendChild(mapWrap);

    // Elev Gain / Max Elev - flat two-column row below the map, no card
    var elevRow=document.createElement('div');
    elevRow.style.cssText='display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:24px';
    elevRow.innerHTML='<div><div style="font-size:20px;font-weight:800;color:var(--t1)">'+(r.elev||'-')+(r.elev?' ft':'')+'</div><div style="font-size:11px;color:var(--t3);margin-top:2px">Elev Gain</div></div>'
      +'<div><div style="font-size:20px;font-weight:800;color:var(--t1)">'+(r.maxElev||'-')+(r.maxElev?' ft':'')+'</div><div style="font-size:11px;color:var(--t3);margin-top:2px">Max Elevation</div></div>';
    wrap.appendChild(elevRow);
  }

  try{ if(typeof renderAchievementStrip==='function') renderAchievementStrip(wrap, r, idx); }catch(e){}

  body.appendChild(wrap);

  // Fetch a real, ride-specific coach insight using the same shared
  // fetchTodaysDecision-style API call, but with a prompt built from
  // this specific ride's numbers rather than "today."
  fetchRideCoachInsight(r, function(err, text){
    var el=document.getElementById('ride-coach-body');
    if(!el) return;
    if(err || !text){ el.textContent='Coach insight unavailable right now.'; return; }
    renderCoachInsightContent(el, text);
  });
}

// Parses the coach response (headline line, "- " bullet observations,
// "Recommendation: " line) into styled HTML matching the reference:
// green bold headline, checkmark/lightning/heart-style icon bullets,
// a distinct Recommendation block, and an Ask Coach button.
function renderCoachInsightContent(el, text){
  var lines=text.split(String.fromCharCode(10)).map(function(l){ return l.trim(); }).filter(Boolean);
  var headline='', bullets=[], recommendation='';
  lines.forEach(function(line){
    if(line.toLowerCase().indexOf('recommendation:')===0){ recommendation=line.replace(/^recommendation:\s*/i,''); }
    else if(line.indexOf('- ')===0){ bullets.push(line.replace(/^-\s*/,'')); }
    else if(!headline){ headline=line; }
  });

  var html='<div style="font-size:15px;font-weight:600;color:var(--t1);line-height:1.4;margin-bottom:14px">'+headline+'</div>';
  if(bullets.length){
    html+='<div style="display:flex;flex-direction:column;gap:10px;margin-bottom:14px">';
    bullets.forEach(function(b){
      html+='<div style="display:flex;gap:8px;align-items:flex-start">'
        +'<span style="flex-shrink:0;margin-top:5px;width:4px;height:4px;border-radius:50%;background:var(--t3)"></span>'
        +'<span style="font-size:13px;color:var(--t2);line-height:1.5">'+b+'</span></div>';
    });
    html+='</div>';
  }
  if(recommendation){
    html+='<div style="border-top:1px solid var(--b1);padding-top:12px;margin-top:2px">'
      +'<div style="font-size:11px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em;margin-bottom:5px">Recommendation</div>'
      +'<div style="font-size:13px;color:var(--t2);line-height:1.5;margin-bottom:14px">'+recommendation+'</div></div>';
  }
  html+='<button id="ride-ask-coach-btn" style="background:var(--s1);border:1px solid var(--b1);border-radius:10px;padding:10px 18px;font-size:13px;font-weight:600;color:var(--t1);cursor:pointer">Ask Coach</button>';
  el.innerHTML=html;
  var askBtn=document.getElementById('ride-ask-coach-btn');
  if(askBtn) askBtn.onclick=function(){ toast('Ask Coach is coming soon'); };
}

// Builds a ride-specific prompt (distinct from fetchTodaysDecision, which
// is about "today," not a specific past ride) and asks for a short
// multi-line coaching read: one headline + 2-3 bullet observations +
// one recommendation, matching the reference design's "Coach" card.
function fetchRideCoachInsight(r, callback){
  var FTP=parseInt(st.ftp||186);
  var maxHR=parseInt(st.maxHR||172);
  var zonePct = r.avgHR ? Math.round((r.avgHR/maxHR)*100) : null;
  var prompt = 'You are a personal cycling coach reviewing a completed ride. '
    +'Ride: '+(r.distance||'?')+' miles, '+(r.duration||'unknown duration')+'. '
    +'Avg power: '+(r.avgPwr||'unknown')+'W, NP: '+(r.np||'unknown')+'W, FTP: '+FTP+'W. '
    +'Avg HR: '+(r.avgHR||'unknown')+'bpm ('+(zonePct?zonePct+'% of max HR':'unknown zone')+'). '
    +'TSS: '+(r.tss||'unknown')+'. Elevation gain: '+(r.elev||0)+'ft. '
    +'Respond in this exact format, no markdown, no extra preamble: '
    +'first line is one short punchy headline describing the ride (max 8 words). '
    +'Then 2-3 short bullet-style observations, each starting with "- ", covering things like time in zone, power/HR steadiness, or fueling if relevant. '
    +'Then a final line starting with "Recommendation: " giving one concrete suggestion for the next session.';

  fetch('https://mikey-food-api2.mgrobinson07.workers.dev/claude',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({ model:'claude-sonnet-4-6', max_tokens:250, messages:[{role:'user',content:prompt}] })
  })
  .then(function(res){ return res.json(); })
  .then(function(d){
    var text = d.content && d.content[0] && d.content[0].text;
    callback(null, (text||'').trim());
  })
  .catch(function(){ callback('Could not reach the coach right now.', null); });
}

// -- ROUTE TAB: hero map (larger), toggle buttons to recolor by
// Power / Heart Rate / Wind, elevation profile underneath as a linked timeline
function renderRideRouteTab(body, r, idx, FTP, BWT){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:14px 16px';

  if(!r.gpsLats || r.gpsLats.length<=5){
    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">No GPS route recorded for this ride.</div>';
    body.appendChild(wrap);
    return;
  }

  // Recolor stat cards - each card shows the metric's value and doubles
  // as the recolor trigger (click to color the route by that metric),
  // collapsing the old display-value + separate-toggle-button pattern into
  // one control. Active card gets an orange ring + tinted background.
  var toggleRow=document.createElement('div');
  toggleRow.style.cssText='display:flex;gap:8px;margin-bottom:12px';
  var windVal = (r.avgWindDir!=null||window._rideWindDirCache!=null) ? 'Direction' : 'Tap to color';
  var modes=[
    {id:'power',label:'Power',val:(r.avgPwr?r.avgPwr+'W':'—'),sub:'Avg'},
    {id:'hr',label:'Heart Rate',val:(r.avgHR?r.avgHR+'':'—'),sub:(r.avgHR?'Avg bpm':'')},
    {id:'wind',label:'Wind',val:'',sub:windVal}
  ];
  var routeColorMode='power';
  var modeBtns={};
  modes.forEach(function(m){
    var btn=document.createElement('button');
    btn.style.cssText='flex:1;min-width:0;padding:10px 8px;border-radius:12px;border:1px solid var(--b1);background:var(--s2);cursor:pointer;text-align:left;transition:box-shadow .12s,background .12s';
    btn.innerHTML='<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--t3);margin-bottom:3px">'+m.label+'</div>'
      +'<div style="font-size:'+(m.val?'17px':'13px')+';font-weight:800;color:var(--t1);line-height:1.1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+(m.val||m.sub)+'</div>'
      +(m.val&&m.sub?'<div style="font-size:9px;color:var(--t3);margin-top:1px">'+m.sub+'</div>':'');
    btn.onclick=function(){ routeColorMode=m.id; updateModeStyles(); redrawRouteMap(); };
    modeBtns[m.id]=btn;
    toggleRow.appendChild(btn);
  });
  wrap.appendChild(toggleRow);

  function updateModeStyles(){
    modes.forEach(function(m){
      var active=m.id===routeColorMode;
      modeBtns[m.id].style.boxShadow=active?'0 0 0 1.5px #FC4C02':'none';
      modeBtns[m.id].style.background=active?'rgba(252,76,2,.08)':'var(--s2)';
    });
  }
  updateModeStyles();

  // Hero map container - taller than the Overview preview, per the
  // reference design's "make the route the hero" direction (roughly
  // 20-30% taller than the app's standard 260px map height).
  var mapCard=document.createElement('div');
  mapCard.id='ride-hero-map-wrap';
  mapCard.style.cssText='border-radius:16px;overflow:hidden;margin-bottom:10px;border:1px solid var(--b1)';
  wrap.appendChild(mapCard);

  var legendRow=document.createElement('div');
  legendRow.id='ride-map-legend';
  legendRow.style.cssText='display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px;justify-content:center';
  wrap.appendChild(legendRow);

  // Elevation profile underneath, as a linked timeline
  if(r.chartEle && r.chartEle.length){
    var eleCard=document.createElement('div');
    eleCard.style.cssText='background:var(--s2);border-radius:14px;padding:14px;border:1px solid var(--b1)';
    eleCard.innerHTML='<div style="font-size:11px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px">Elevation</div>'
      +buildLineChart(r.chartEle,'#27AE60','ft',r.elev?('+'+r.elev+' ft gain'):'');
    wrap.appendChild(eleCard);
  } else {
    var eleNote=document.createElement('div');
    eleNote.style.cssText='background:var(--s2);border-radius:14px;padding:14px;border:1px solid var(--b1);color:var(--t3);font-size:12px;line-height:1.5';
    eleNote.innerHTML='<div style="font-size:11px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.06em;margin-bottom:6px">Elevation</div>'
      +(r.elev?('+'+r.elev+' ft total gain. '):'')+'No elevation profile stored for this ride &mdash; it was imported without a per-point altitude stream.';
    wrap.appendChild(eleNote);
  }

  body.appendChild(wrap);

  function buildWindColoredMap(){
    // Retroactive wind classification: uses today's live wind reading as
    // a stand-in bearing/speed reference for coloring, same honest
    // limitation noted on the Weather Map tab - true point-in-time
    // historical wind requires the archive API call made on the Weather
    // tab; this toggle gives a quick visual read using current direction
    // as an approximation when historical data has not loaded yet.
    var windDeg = window._rideWindDirCache;
    var lats=r.lats||r.gpsLats, lons=r.lons||r.gpsLons;
    var mapId='ride-route-map-'+idx;
    var html='<div id="'+mapId+'" style="width:100%;height:340px"></div>';
    mapCard.innerHTML=html;
    setTimeout(function(){
      var mapEl=document.getElementById(mapId);
      if(!mapEl||typeof L==='undefined') return;
      var map=L.map(mapId,{zoomControl:true,scrollWheelZoom:false});
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);
      var pts=lats.map(function(la,i){return[la,lons[i]];});
      if(windDeg==null){
        L.polyline(pts,{color:'#94a3b8',weight:4,opacity:.85}).addTo(map);
      } else {
        var step=Math.max(1,Math.floor(pts.length/40));
        for(var i=0;i<pts.length-step;i+=step){
          var p1=pts[i], p2=pts[Math.min(pts.length-1,i+step)];
          var bearing=(Math.atan2(p2[1]-p1[1],p2[0]-p1[0])*180/Math.PI+360)%360;
          var windToward=(windDeg+180)%360;
          var diff=Math.abs(((bearing-windToward+540)%360)-180);
          var col = diff<45 ? '#1D9E75' : diff>135 ? '#E24B4A' : '#BA7517';
          L.polyline([p1,p2],{color:col,weight:4,opacity:.85}).addTo(map);
        }
      }
      L.circleMarker(pts[0],{radius:7,fillColor:'#27AE60',color:'#fff',weight:2,fillOpacity:1}).addTo(map);
      L.circleMarker(pts[pts.length-1],{radius:7,fillColor:'#FC4C02',color:'#fff',weight:2,fillOpacity:1}).addTo(map);
      map.fitBounds(L.latLngBounds(pts),{padding:[30,30]});
      // Wind-direction compass overlay in the top-right corner of the map.
      // winddirection is the "from" bearing; the arrow points the way the
      // wind is blowing TO (from + 180), which is what a rider feels.
      if(windDeg!=null){
        var dirArr=['N','NE','E','SE','S','SW','W','NW'];
        var fromLabel=dirArr[Math.round(windDeg/45)%8];
        var blowTo=(windDeg+180)%360;
        var ov=document.createElement('div');
        ov.style.cssText='position:absolute;top:10px;right:10px;z-index:500;background:rgba(20,20,22,.82);border:1px solid rgba(255,255,255,.15);border-radius:12px;padding:8px 10px;display:flex;align-items:center;gap:8px;backdrop-filter:blur(4px)';
        ov.innerHTML='<div style="transform:rotate('+blowTo+'deg);display:flex"><svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="#4D9FFF" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="20" x2="12" y2="5"/><polyline points="6 11 12 5 18 11"/></svg></div>'
          +'<div style="line-height:1.1"><div style="font-size:12px;font-weight:800;color:#fff">'+fromLabel+' wind</div><div style="font-size:10px;color:rgba(255,255,255,.65)">from '+Math.round(windDeg)+'&deg;</div></div>';
        mapEl.appendChild(ov);
      }
      setTimeout(function(){ try{map.invalidateSize();}catch(e){} },300);
      window['_wxmap_ridedetail']=map;
    },100);
  }

  function redrawRouteMap(){
    if(routeColorMode==='power'){
      mapCard.innerHTML=buildRouteMap(r.lats||r.gpsLats, r.lons||r.gpsLons, r.chartPwr||[], FTP).replace('height:260px','height:340px');
      legendRow.innerHTML=['<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#94a3b8"></span>Z1-2</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#3b82f6"></span>Z3</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#22c55e"></span>Z4</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#f59e0b"></span>Z5</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#ef4444"></span>Z6+</span>'].join('');
    } else if(routeColorMode==='hr'){
      mapCard.innerHTML=buildRouteMapHR(r.lats||r.gpsLats, r.lons||r.gpsLons, r.chartHR||[], parseInt(st.maxHR||172));
      legendRow.innerHTML=['<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#64748b"></span>Z1</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#3b82f6"></span>Z2</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#22c55e"></span>Z3</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#f59e0b"></span>Z4</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#ef4444"></span>Z5</span>'].join('');
    } else {
      buildWindColoredMap();
      legendRow.innerHTML=['<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#1D9E75"></span>Tailwind</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#E24B4A"></span>Headwind</span>',
        '<span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--t2)"><span style="width:10px;height:10px;border-radius:50%;background:#BA7517"></span>Crosswind</span>'].join('');
      if(window._rideWindDirCache==null){
        fetch('https://api.open-meteo.com/v1/forecast?latitude=42.9634&longitude=-85.6681&current=winddirection_10m')
          .then(function(res){ return res.json(); })
          .then(function(d){ window._rideWindDirCache = d && d.current ? d.current.winddirection_10m : null; if(routeColorMode==='wind') buildWindColoredMap(); })
          .catch(function(){});
      }
    }
  }

  redrawRouteMap();
}

// HR-zone equivalent of buildRouteMap - colors route segments by heart
// rate zone instead of power zone, same rendering approach.
function buildRouteMapHR(lats, lons, hrData, maxHR){
  if(!lats||!lats.length) return '';
  if(lons && lons.length!==lats.length){
    var minLen=Math.min(lats.length,lons.length);
    lats=lats.slice(0,minLen); lons=lons.slice(0,minLen);
  }
  if(!window._mapCount) window._mapCount=0; window._mapCount++; var mapId='leaflet-map-hr-'+window._mapCount;
  var html='<div id="'+mapId+'" style="width:100%;height:340px"></div>';
  setTimeout(function(){
    var mapEl=document.getElementById(mapId);
    if(!mapEl||typeof L==='undefined') return;
    var map=L.map(mapId,{zoomControl:true,scrollWheelZoom:false});
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);
    if(hrData && hrData.length>5){
      var step=Math.max(1,Math.floor(lats.length/hrData.length));
      var currentColor='#64748b';
      var segPoints=[[lats[0],lons[0]]];
      for(var i=1;i<lats.length;i++){
        var pIdx=Math.floor(i/step);
        var hr=hrData[Math.min(pIdx,hrData.length-1)]||0;
        var pct=hr/maxHR;
        var col=pct>=.9?'#ef4444':pct>=.8?'#f59e0b':pct>=.7?'#22c55e':pct>=.6?'#3b82f6':'#64748b';
        if(col!==currentColor && segPoints.length>1){
          L.polyline(segPoints,{color:currentColor,weight:4,opacity:.85}).addTo(map);
          segPoints=[segPoints[segPoints.length-1]];
          currentColor=col;
        }
        segPoints.push([lats[i],lons[i]]);
      }
      if(segPoints.length>1) L.polyline(segPoints,{color:currentColor,weight:4,opacity:.85}).addTo(map);
    } else {
      var coords=lats.map(function(lat,i){return[lat,lons[i]];});
      L.polyline(coords,{color:'#ef4444',weight:4,opacity:.9}).addTo(map);
    }
    var coords2=lats.map(function(lat,i){return[lat,lons[i]];});
    L.circleMarker(coords2[0],{radius:7,fillColor:'#27AE60',color:'#fff',weight:2,fillOpacity:1}).addTo(map);
    L.circleMarker(coords2[coords2.length-1],{radius:7,fillColor:'#FC4C02',color:'#fff',weight:2,fillOpacity:1}).addTo(map);
    map.fitBounds(L.latLngBounds(coords2),{padding:[30,30]});
    setTimeout(function(){ try{map.invalidateSize();}catch(e){} },300);
  },100);
  return html;
}

// -- PERFORMANCE TAB: power/HR line charts, zone breakdowns, peak power curve
function renderRidePerformanceTab(body, r, idx, FTP, BWT){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:14px 16px';
  var html='';

  // Dedicated metric cards with big Avg/Max above a sparkline, matching
  // the reference's Charts tab layout. Only Power and Heart Rate have
  // real per-point chart data in this app (no cadence/speed time-series
  // exist yet) - built honestly for what is actually available rather
  // than inventing placeholder charts for the other two.
  if(r.chartPwr && r.chartPwr.length){
    html+='<div style="background:var(--s2);border-radius:14px;padding:16px;margin-bottom:10px">'
      +'<div style="font-size:12px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.04em;margin-bottom:8px">Power (W)</div>'
      +'<div style="display:flex;gap:20px;align-items:baseline;margin-bottom:10px">'
      +'<div><span style="font-size:22px;font-weight:800;color:var(--t1)">'+(r.avgPwr||'-')+'</span><span style="font-size:11px;color:var(--t3)"> Avg</span></div>'
      +'<div><span style="font-size:22px;font-weight:800;color:var(--t1)">'+(r.maxPwr||'-')+'</span><span style="font-size:11px;color:var(--t3)"> Max</span></div>'
      +'</div>'
      +buildLineChart(r.chartPwr,'#FC4C02','W','')+'</div>';
  }
  if(r.chartHR && r.chartHR.length){
    html+='<div style="background:var(--s2);border-radius:14px;padding:16px;margin-bottom:10px">'
      +'<div style="font-size:12px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.04em;margin-bottom:8px">Heart Rate (bpm)</div>'
      +'<div style="display:flex;gap:20px;align-items:baseline;margin-bottom:10px">'
      +'<div><span style="font-size:22px;font-weight:800;color:var(--t1)">'+(r.avgHR||'-')+'</span><span style="font-size:11px;color:var(--t3)"> Avg</span></div>'
      +'<div><span style="font-size:22px;font-weight:800;color:var(--t1)">'+(r.maxHR||'-')+'</span><span style="font-size:11px;color:var(--t3)"> Max</span></div>'
      +'</div>'
      +buildLineChart(r.chartHR,'#ef4444','bpm','')+'</div>';
  }
  if(r.cadence){
    html+='<div style="background:var(--s2);border-radius:14px;padding:16px;margin-bottom:10px">'
      +'<div style="font-size:12px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.04em;margin-bottom:8px">Cadence (rpm)</div>'
      +'<div style="font-size:22px;font-weight:800;color:var(--t1)">'+r.cadence+'<span style="font-size:11px;color:var(--t3);font-weight:600"> Avg</span></div>'
      +'<div style="font-size:11px;color:var(--t3);margin-top:6px">Per-second cadence not recorded for this ride - only the ride average is available.</div></div>';
  }

  var hrColHtml='';
  if(r.avgHR){
    var cMaxHR=parseInt(st.maxHR||172);
    var cZones=[
      {n:'Z1 Recovery',lo:0,hi:Math.round(cMaxHR*0.6),c:'#8a8a8a'},
      {n:'Z2 Endurance',lo:Math.round(cMaxHR*0.6)+1,hi:Math.round(cMaxHR*0.7),c:'#0F6E56'},
      {n:'Z3 Tempo',lo:Math.round(cMaxHR*0.7)+1,hi:Math.round(cMaxHR*0.8),c:'#BA7517'},
      {n:'Z4 Threshold',lo:Math.round(cMaxHR*0.8)+1,hi:Math.round(cMaxHR*0.9),c:'#FC4C02'},
      {n:'Z5 VO2 Max',lo:Math.round(cMaxHR*0.9)+1,hi:cMaxHR,c:'#ef4444'}
    ];
    var avgZone=cZones.find(function(z){return r.avgHR>=z.lo&&r.avgHR<=z.hi;})||cZones[0];
    hrColHtml+='<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:var(--t3);margin-bottom:6px">HR Zone (avg '+r.avgHR+' &mdash; '+avgZone.n+')</div>';
    hrColHtml+='<div style="display:flex;flex-direction:column;align-items:flex-start;gap:5px">';
    cZones.forEach(function(z){
      var isActive=z.n===avgZone.n;
      hrColHtml+='<div style="display:inline-flex;align-items:center;gap:5px;background:var(--s2);border-radius:20px;padding:4px 10px 4px 6px;'+(isActive?'box-shadow:0 0 0 1.5px '+z.c+';':'')+'">'
        +'<span style="width:7px;height:7px;border-radius:50%;background:'+z.c+';flex-shrink:0"></span>'
        +'<span style="font-size:10px;font-weight:'+(isActive?'800':'600')+';color:var(--t1);white-space:nowrap">'+z.n+'</span>'
        +'<span style="font-size:9px;font-weight:700;color:'+z.c+';white-space:nowrap">'+z.lo+'&ndash;'+z.hi+'</span></div>';
    });
    hrColHtml+='</div>';
  }

  var powerColHtml='<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:var(--t3);margin-bottom:6px">Power</div>'
    +'<div style="background:var(--s1);border-radius:14px;border:1px solid var(--b1);padding:8px;flex:1;display:flex;flex-direction:column">'
    +'<div style="display:grid;grid-template-columns:repeat(3,1fr);grid-template-rows:1fr 1fr;gap:5px;flex:1">';
  [{v:(r.avgPwr||'-')+(r.avgPwr?'W':''),l:'Avg Pwr'},{v:(r.np||'-')+(r.np?'W':''),l:'Norm Pwr',c:'#FC4C02'},{v:r.ifPct?(r.ifPct+'%'):'-',l:'Int. Fctr'},{v:r.workKj?(r.workKj+' kJ'):'-',l:'Work'},{v:r.max20?(r.max20+'W'):'-',l:'20m Max'},{v:r.maxPwr?(r.maxPwr+'W'):'-',l:'Peak Pwr'}]
  .forEach(function(s){
    powerColHtml+='<div style="background:var(--s2);border-radius:8px;padding:6px 4px 6px 8px;text-align:left;display:flex;flex-direction:column;align-items:flex-start;justify-content:center">'
      +'<div style="font-size:12px;font-weight:800;color:'+(s.c||'var(--t1)')+'">'+s.v+'</div>'
      +'<div style="font-size:7px;text-transform:uppercase;letter-spacing:.04em;color:var(--t3);margin-top:2px">'+s.l+'</div></div>';
  });
  powerColHtml+='</div></div>';

  html+='<div style="display:flex;gap:10px;margin-bottom:14px;align-items:stretch">';
  if(hrColHtml) html+='<div style="flex:1;min-width:0;display:flex;flex-direction:column">'+hrColHtml+'</div>';
  html+='<div style="flex:1;min-width:0;display:flex;flex-direction:column">'+powerColHtml+'</div>';
  html+='</div>';

  if(r.z1s||r.z2s||r.z3s||r.z4s||r.z5s){
    var maxHRset=r.maxHR||180;
    var hrZones=[
      {n:'Zone 1',range:'< '+(Math.round(maxHRset*.6))+'bpm',s:r.z1s||0,c:'#64748b'},
      {n:'Zone 2',range:(Math.round(maxHRset*.6))+'-'+(Math.round(maxHRset*.7))+'bpm',s:r.z2s||0,c:'#3b82f6'},
      {n:'Zone 3',range:(Math.round(maxHRset*.7))+'-'+(Math.round(maxHRset*.8))+'bpm',s:r.z3s||0,c:'#22c55e'},
      {n:'Zone 4',range:(Math.round(maxHRset*.8))+'-'+(Math.round(maxHRset*.9))+'bpm',s:r.z4s||0,c:'#f59e0b'},
      {n:'Zone 5',range:'> '+(Math.round(maxHRset*.9))+'bpm',s:r.z5s||0,c:'#ef4444'}
    ];
    var totalHR=hrZones.reduce(function(a,b){return a+b.s;},0)||1;
    html+='<div style="background:var(--s2);border-radius:14px;padding:16px;margin-bottom:14px">'
      +'<div style="font-size:11px;font-weight:700;color:var(--t3);margin-bottom:10px;text-transform:uppercase;letter-spacing:.08em">Time in HR Zone</div>';
    hrZones.forEach(function(z){
      var pct=Math.round(z.s/totalHR*100);
      var mins=Math.floor(z.s/60);
      html+='<div style="margin-bottom:8px">'
        +'<div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px">'
        +'<span style="font-weight:600;color:var(--t1)">'+z.n+' <span style="font-weight:400;color:var(--t3)">'+z.range+'</span></span>'
        +'<span style="color:var(--t3)">'+mins+'min <span style="font-weight:700;color:'+z.c+'">'+pct+'%</span></span></div>'
        +'<div style="height:6px;background:var(--s3);border-radius:3px"><div style="height:6px;background:'+z.c+';border-radius:3px;width:'+pct+'%"></div></div></div>';
    });
    html+='</div>';
  }

  if(r.z1s||r.z2s||r.z3s||r.z4s||r.z5s||r.z6s){
    html+='<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:var(--t3);margin-bottom:8px">Power Zones</div>';
    html+='<div style="background:var(--s2);border-radius:14px;padding:14px;margin-bottom:14px">';
    var pZones=[
      {n:'Z1 Recovery',s:r.z1s||0,c:'#64748b'},{n:'Z2 Endurance',s:r.z2s||0,c:'#3b82f6'},
      {n:'Z3 Tempo',s:r.z3s||0,c:'#22c55e'},{n:'Z4 Threshold',s:r.z4s||0,c:'#f59e0b'},
      {n:'Z5 VO2max',s:r.z5s||0,c:'#ef4444'},{n:'Z6 Anaerobic',s:r.z6s||0,c:'#a855f7'}
    ];
    var totalPZ=pZones.reduce(function(a,b){return a+b.s;},0)||1;
    html+='<div style="display:flex;height:12px;border-radius:6px;overflow:hidden;margin-bottom:12px">';
    pZones.forEach(function(z){
      var pct=Math.round(z.s/totalPZ*100);
      if(pct>0) html+='<div style="background:'+z.c+';width:'+pct+'%;opacity:.85"></div>';
    });
    html+='</div>';
    pZones.forEach(function(z){
      var pct=Math.round(z.s/totalPZ*100);
      var mins=Math.floor(z.s/60);
      if(!mins&&!pct) return;
      html+='<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">'
        +'<div style="width:10px;height:10px;border-radius:3px;background:'+z.c+';flex-shrink:0"></div>'
        +'<div style="flex:1;font-size:13px;color:var(--t1);font-weight:600">'+z.n+'</div>'
        +'<div style="font-size:12px;color:var(--t3)">'+mins+'min</div>'
        +'<div style="font-size:12px;font-weight:700;color:'+z.c+';min-width:32px;text-align:right">'+pct+'%</div></div>';
    });
    html+='</div>';
  }

  if(r.powerCurve && Object.keys(r.powerCurve).length){
    var peakDurs=[{d:5,l:'5s'},{d:15,l:'15s'},{d:30,l:'30s'},{d:60,l:'1min'},{d:120,l:'2min'},{d:300,l:'5min'},{d:600,l:'10min'},{d:1200,l:'20min'},{d:1800,l:'30min'},{d:3600,l:'60min'}];
    var globalBest={};
    st.rides.forEach(function(ride,ri){
      if(ri===idx) return;
      if(ride.powerCurve) Object.keys(ride.powerCurve).forEach(function(d){
        if(!globalBest[d]||ride.powerCurve[d]>globalBest[d]) globalBest[d]=ride.powerCurve[d];
      });
    });
    html+='<div style="font-size:11px;font-weight:700;color:var(--t3);margin-bottom:8px;text-transform:uppercase;letter-spacing:.08em">Peak Power Curve</div>';
    html+='<div style="border:1px solid var(--b1);border-radius:14px;overflow:hidden">';
    html+='<div style="display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr) 1fr auto;padding:7px 10px;background:var(--s2)">'
      +'<div style="font-size:10px;font-weight:700;color:var(--t3)">Duration</div>'
      +'<div style="font-size:10px;font-weight:700;color:var(--t3);text-align:center">Watts</div>'
      +'<div style="font-size:10px;font-weight:700;color:var(--t3);text-align:right">W/kg</div>'
      +'<div style="font-size:10px;font-weight:700;color:var(--t3);text-align:right;padding-left:8px">PR</div></div>';
    peakDurs.forEach(function(pd,i){
      var w=r.powerCurve[pd.d]; if(!w) return;
      var wkg2=(w/BWT*2.20462).toFixed(1);
      var zc=w>=FTP*1.21?'#a855f7':w>=FTP*1.06?'#ef4444':w>=FTP*.91?'#f59e0b':w>=FTP*.76?'#22c55e':'#3b82f6';
      var isPR=!globalBest[pd.d]||w>=globalBest[pd.d];
      var bg=i%2===0?'var(--s1)':'var(--s2)';
      html+='<div style="display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr) 1fr auto;padding:9px 10px;background:'+bg+';border-top:1px solid var(--b1)">'
        +'<div style="font-size:13px;font-weight:600;color:var(--t1)">'+pd.l+'</div>'
        +'<div style="font-size:15px;font-weight:800;color:'+zc+';text-align:center">'+w+'</div>'
        +'<div style="font-size:13px;color:var(--t3);text-align:right">'+wkg2+'</div>'
        +'<div style="text-align:right;padding-left:8px">'+(isPR?'<span style="background:#FFD700;color:#7A5800;font-size:9px;font-weight:800;padding:2px 6px;border-radius:8px">PR</span>':'')+'</div></div>';
    });
    html+='</div>';
  }

  // -- ACHIEVEMENT STRIP: honest, data-backed highlights for THIS ride.
  // Two rows. (1) PRs: genuine records this ride set - power-duration bests
  // measured against every OTHER ride's power curve, plus all-time distance/
  // NP/TSS bests. Gold chips, only when a real record was set. (2) Notable
  // efforts: this ride's standout raw numbers, shown as neutral chips
  // regardless of record status. No fabricated segments/climbs/kudos -
  // that data does not exist in this app, so it is not invented here.
  (function(){
    var achHtml='';

    // (1) Power-duration PRs vs all other rides (mirrors the Peak Power
    // Curve table's globalBest logic for consistency).
    var prChips=[];
    if(r.powerCurve && Object.keys(r.powerCurve).length){
      var durLabels={5:'5s',15:'15s',30:'30s',60:'1min',120:'2min',300:'5min',600:'10min',1200:'20min',1800:'30min',3600:'60min'};
      var gBest={};
      (st.rides||[]).forEach(function(ride,ri){
        if(ri===idx || ride.deleted) return;
        if(ride.powerCurve) Object.keys(ride.powerCurve).forEach(function(d){
          if(!gBest[d]||ride.powerCurve[d]>gBest[d]) gBest[d]=ride.powerCurve[d];
        });
      });
      // Only surface the most meaningful PR durations to avoid a wall of chips.
      [1200,600,300,60,5].forEach(function(d){
        var w=r.powerCurve[d];
        if(w && (!gBest[d] || w>gBest[d])){
          prChips.push((durLabels[d]||d+'s')+' power '+w+'W');
        }
      });
    }

    // (2) All-time bests set by this ride (distance / NP / TSS), computed
    // against every other ride with the same sanity ceilings used elsewhere.
    var NP_CEILING=600, TSS_CEILING=600;
    var otherMaxDist=0, otherMaxNP=0, otherMaxTSS=0;
    (st.rides||[]).forEach(function(ride,ri){
      if(ri===idx || ride.deleted) return;
      var dd=parseFloat(ride.distance||0); if(dd>otherMaxDist) otherMaxDist=dd;
      if(ride.np && ride.np>otherMaxNP && ride.np<=NP_CEILING) otherMaxNP=ride.np;
      if(ride.tss && ride.tss>otherMaxTSS && ride.tss<=TSS_CEILING) otherMaxTSS=ride.tss;
    });
    var thisDist=parseFloat(r.distance||0);
    if(thisDist>0 && thisDist>otherMaxDist) prChips.push('Longest ride '+thisDist.toFixed(1)+' mi');
    if(r.np && r.np<=NP_CEILING && r.np>otherMaxNP) prChips.push('Best NP '+r.np+'W');
    if(r.tss && r.tss<=TSS_CEILING && r.tss>otherMaxTSS) prChips.push('Highest TSS '+Math.round(r.tss));

    // (3) Notable-effort highlights - this ride's standout numbers.
    var effChips=[];
    if(r.max20) effChips.push({v:r.max20+'W',l:'20-min peak'});
    if(r.maxPwr) effChips.push({v:r.maxPwr+'W',l:'Peak power'});
    if(r.workKj) effChips.push({v:r.workKj+' kJ',l:'Work'});
    if(r.elev) effChips.push({v:'+'+r.elev+' ft',l:'Climbing'});
    if(thisDist>0) effChips.push({v:thisDist.toFixed(1)+' mi',l:'Distance'});

    if(prChips.length || effChips.length){
      achHtml+='<div style="background:var(--s2);border-radius:14px;padding:16px;margin-bottom:14px">'
        +'<div style="font-size:11px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px">Achievements</div>';

      if(prChips.length){
        achHtml+='<div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:'+(effChips.length?'12px':'0')+'">';
        prChips.forEach(function(t){
          achHtml+='<span style="display:inline-flex;align-items:center;gap:4px;background:rgba(255,215,0,.14);border:1px solid rgba(255,215,0,.35);border-radius:20px;padding:5px 11px;font-size:12px;font-weight:700;color:var(--t1)">'
            +'<span style="font-size:11px">🏆</span>'+t+'</span>';
        });
        achHtml+='</div>';
      }

      if(effChips.length){
        achHtml+='<div style="display:flex;flex-wrap:wrap;gap:6px">';
        effChips.forEach(function(c){
          achHtml+='<span style="display:inline-flex;align-items:baseline;gap:5px;background:var(--s1);border:1px solid var(--b1);border-radius:20px;padding:5px 11px;font-size:12px;color:var(--t2)">'
            +'<span style="font-weight:800;color:var(--t1)">'+c.v+'</span>'
            +'<span style="font-size:10px;color:var(--t3)">'+c.l+'</span></span>';
        });
        achHtml+='</div>';
      }

      achHtml+='</div>';
    }
    html+=achHtml;
  })();

  wrap.innerHTML=html;
  body.appendChild(wrap);
}

// -- WEATHER TAB: retroactive conditions during this specific ride, using
// Open-Meteo's historical archive API rather than current/forecast data.
function renderRideWeatherTab(body, r, idx){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:14px 16px';

  if(!r.date){
    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">No date recorded for this ride, cannot look up historical weather.</div>';
    body.appendChild(wrap);
    return;
  }

  wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">Looking up conditions for this ride&hellip;</div>';
  body.appendChild(wrap);

  fetch('https://archive-api.open-meteo.com/v1/archive?latitude=42.9634&longitude=-85.6681'
    +'&start_date='+r.date+'&end_date='+r.date
    +'&hourly=temperature_2m,windspeed_10m,winddirection_10m,windgusts_10m,precipitation'
    +'&temperature_unit=fahrenheit&windspeed_unit=mph&timezone=America%2FChicago')
  .then(function(res){ if(!res.ok) throw new Error('Weather history returned '+res.status); return res.json(); })
  .then(function(data){
    renderRideWeatherContent(wrap, r, data && data.hourly);
  })
  .catch(function(err){
    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">Could not load historical weather for this ride.<br>'+(err&&err.message?err.message:'')+'</div>';
  });
}

function renderRideWeatherContent(wrap, r, hourly){
  if(!hourly || !hourly.time || !hourly.time.length){
    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">No historical weather available for this date.</div>';
    return;
  }

  // Narrow to the ride's actual start/end hours if we have a start time,
  // otherwise use the whole day as a reasonable fallback.
  var startHour=0, endHour=hourly.time.length-1;
  if(r.startTime){
    var startDt=new Date(r.startTime);
    startHour=startDt.getHours();
    var durMinutes = r.duration ? parseDurationToMinutes_(r.duration) : 90;
    endHour = Math.min(hourly.time.length-1, startHour + Math.ceil(durMinutes/60));
  }

  var temps=hourly.temperature_2m.slice(startHour,endHour+1);
  var winds=hourly.windspeed_10m.slice(startHour,endHour+1);
  var dirs=hourly.winddirection_10m.slice(startHour,endHour+1);
  var gusts=hourly.windgusts_10m.slice(startHour,endHour+1);

  var avgTemp=Math.round(temps.reduce(function(a,b){return a+b;},0)/temps.length);
  var startTemp=Math.round(temps[0]);
  var endTemp=Math.round(temps[temps.length-1]);
  var avgWind=Math.round(winds.reduce(function(a,b){return a+b;},0)/winds.length);
  var maxGust=Math.round(Math.max.apply(null,gusts));
  var maxGustIdx=gusts.indexOf(Math.max.apply(null,gusts));

  // Tailwind/headwind/crosswind % using the ride's overall bearing (start
  // to end point) as a simple stand-in for per-segment direction, since
  // full per-point correlation with historical hourly wind needs the
  // route timing lined up minute-by-minute - a reasonable first pass,
  // not pretending to be more precise than the data actually supports.
  var windPct = {tail:0, head:0, cross:0};
  if(r.gpsLats && r.gpsLats.length>5){
    var lats=r.lats||r.gpsLats, lons=r.lons||r.gpsLons;
    var overallBearing=(Math.atan2(lons[lons.length-1]-lons[0], lats[lats.length-1]-lats[0])*180/Math.PI+360)%360;
    var avgDir=dirs.reduce(function(a,b){return a+b;},0)/dirs.length;
    var windToward=(avgDir+180)%360;
    var diff=Math.abs(((overallBearing-windToward+540)%360)-180);
    if(diff<45){ windPct.tail=100; }
    else if(diff>135){ windPct.head=100; }
    else { windPct.cross=100; }
  }

  var dirArr=['N','NE','E','SE','S','SW','W','NW'];
  var avgDirLabel=dirArr[Math.round((dirs.reduce(function(a,b){return a+b;},0)/dirs.length)/45)%8];

  wrap.innerHTML='';

  var summaryCard=document.createElement('div');
  summaryCard.style.cssText='background:var(--s2);border-radius:14px;padding:16px;margin-bottom:12px';
  summaryCard.innerHTML='<div style="font-size:11px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:10px">Conditions During This Ride</div>'
    +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">'
    +'<div><div style="font-size:20px;font-weight:800;color:var(--t1)">'+avgTemp+'&deg;F</div><div style="font-size:11px;color:var(--t3)">Avg temp ('+startTemp+'&deg;&rarr;'+endTemp+'&deg;)</div></div>'
    +'<div><div style="font-size:20px;font-weight:800;color:var(--t1)">'+avgWind+'mph '+avgDirLabel+'</div><div style="font-size:11px;color:var(--t3)">Avg wind, gusts to '+maxGust+'mph</div></div>'
    +'</div>';
  wrap.appendChild(summaryCard);

  var windBreakdown=document.createElement('div');
  windBreakdown.style.cssText='background:var(--s2);border-radius:14px;padding:16px;margin-bottom:12px';
  windBreakdown.innerHTML='<div style="font-size:11px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:10px">Wind Breakdown</div>'
    +'<div style="display:flex;height:12px;border-radius:6px;overflow:hidden;margin-bottom:10px">'
    +(windPct.tail>0?'<div style="background:#1D9E75;width:'+windPct.tail+'%"></div>':'')
    +(windPct.head>0?'<div style="background:#E24B4A;width:'+windPct.head+'%"></div>':'')
    +(windPct.cross>0?'<div style="background:#BA7517;width:'+windPct.cross+'%"></div>':'')
    +'</div>'
    +'<div style="display:flex;gap:14px;flex-wrap:wrap;font-size:12px;color:var(--t2)">'
    +'<span><span style="color:#1D9E75;font-weight:700">'+windPct.tail+'%</span> tailwind</span>'
    +'<span><span style="color:#E24B4A;font-weight:700">'+windPct.head+'%</span> headwind</span>'
    +'<span><span style="color:#BA7517;font-weight:700">'+windPct.cross+'%</span> crosswind</span>'
    +'</div>'
    +'<div style="font-size:11px;color:var(--t3);margin-top:10px;line-height:1.5">Based on overall route direction vs. average wind during the ride window. Strongest gust: '+maxGust+'mph around '+formatHour12(hourly.time[startHour+maxGustIdx]?new Date(hourly.time[startHour+maxGustIdx]).getHours():startHour)+'.</div>';
  wrap.appendChild(windBreakdown);

  // Temperature progression chart
  if(temps.length>1){
    var tempCard=document.createElement('div');
    tempCard.style.cssText='background:var(--s2);border-radius:14px;padding:14px';
    tempCard.innerHTML='<div style="font-size:11px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px">Temperature During Ride</div>'
      +buildLineChart(temps,'#FC4C02','&deg;F','');
    wrap.appendChild(tempCard);
  }
}

// Rough duration string ("1:30:07" or "1h 30m") to minutes, for narrowing
// the historical weather window to roughly when the ride happened.
function parseDurationToMinutes_(dur){
  if(!dur) return 90;
  var parts = String(dur).split(':');
  if(parts.length>=2){
    var h=parseInt(parts[0])||0, m=parseInt(parts[1])||0;
    return h*60+m;
  }
  var hMatch=String(dur).match(/(\d+)h/);
  var mMatch=String(dur).match(/(\d+)m/);
  return (hMatch?parseInt(hMatch[1])*60:0)+(mMatch?parseInt(mMatch[1]):0)||90;
}

// -- EQUIPMENT TAB: which bike was used, its mileage, and maintenance
// status/next-service estimate, tying this ride into Garage's real data.
function renderRideEquipmentTab(body, r, idx){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:14px 16px';

  ensureBikes();
  var bike = null;
  if(r.gearId){
    bike = (st.bikes||[]).find(function(b){ return b.id===r.gearId || b.stravaGearId===r.gearId; });
  }
  if(!bike && r.gearName){
    bike = (st.bikes||[]).find(function(b){ return b.name===r.gearName; });
  }

  // Shoes: resolved by the same gear fields as bikes. Strava rides carry a
  // gear_id (mapped to a name via st.stravaGearMap); ICU CSV imports carry
  // the gear display name directly on r.gearName. Runs resolve to a shoe
  // here rather than a bike.
  if(!bike){
    var shoe = null;
    if(r.gearId){
      // gearId -> shoe name via the Strava gear map, then match st.shoes by name
      var mappedName = (st.stravaGearMap && st.stravaGearMap[r.gearId]) || null;
      if(mappedName){
        shoe = (st.shoes||[]).find(function(s){ return s.name===mappedName || s.id===r.gearId; });
      }
      if(!shoe){
        shoe = (st.shoes||[]).find(function(s){ return s.id===r.gearId; });
      }
    }
    if(!shoe && r.gearName){
      shoe = (st.shoes||[]).find(function(s){ return s.name===r.gearName; });
    }

    if(shoe){
      var maxMi = shoe.maxMiles||400;
      var mi = shoe.miles||0;
      var pct = Math.min(100, Math.round(mi/maxMi*100));
      var remaining = Math.max(0, maxMi - mi);
      var pctColor = pct>80?'#ef4444':pct>60?'#BA7517':'#0F6E56';
      var statusLabel = pct>80?'Replace soon':pct>60?'Wearing in':'Good';

      var shoeCard=document.createElement('div');
      shoeCard.style.cssText='border-radius:16px;overflow:hidden;position:relative;padding:16px;margin-bottom:14px;background:linear-gradient(160deg,#2a2a2e,#1c1c1f)';
      shoeCard.innerHTML='<div style="font-size:17px;font-weight:800;color:#fff">'+shoe.name+'</div>'
        +'<div style="font-size:12px;color:rgba(255,255,255,.85);margin-top:2px">'+mi+' mi total &middot; Running shoes</div>';
      wrap.appendChild(shoeCard);

      var wearCard=document.createElement('div');
      wearCard.style.cssText='background:var(--s2);border-radius:14px;padding:14px 16px';
      wearCard.innerHTML='<div style="font-size:11px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:10px">Wear</div>'
        +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">'
        +'<span style="font-size:13px;color:var(--t1);font-weight:600">'+mi+' mi <span style="font-size:11px;color:var(--t3);font-weight:400">/ '+maxMi+' mi</span></span>'
        +'<span style="font-size:12px;font-weight:700;color:'+pctColor+'">'+statusLabel+'</span></div>'
        +'<div style="height:5px;background:var(--s3);border-radius:3px;margin-bottom:6px"><div style="height:5px;background:'+pctColor+';border-radius:3px;width:'+pct+'%"></div></div>'
        +'<div style="font-size:11px;color:var(--t3)">'+remaining+' mi remaining before replacement</div>';
      wrap.appendChild(wearCard);

      body.appendChild(wrap);
      return;
    }

    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">No equipment logged for this activity.</div>';
    body.appendChild(wrap);
    return;
  }

  var badge = bikeStatusBadge(bike);
  var photoStyle = bike.photo
    ? 'background-image:linear-gradient(0deg,rgba(0,0,0,.85) 0%,rgba(0,0,0,.1) 60%,transparent 100%),url('+bike.photo+');background-size:cover;background-position:center 40%'
    : 'background:linear-gradient(160deg,#2a2a2e,#1c1c1f)';

  var card=document.createElement('div');
  card.style.cssText='border-radius:16px;overflow:hidden;position:relative;height:160px;margin-bottom:14px;'+photoStyle;
  card.innerHTML='<div style="position:absolute;bottom:0;left:0;right:0;padding:14px 16px">'
    +'<div style="font-size:17px;font-weight:800;color:#fff">'+bike.name+'</div>'
    +'<div style="font-size:12px;color:rgba(255,255,255,.85);margin-top:2px">'+(bike.miles||0)+' mi total &middot; '+bike.type+'</div>'
    +'</div>';
  wrap.appendChild(card);

  var maintCard=document.createElement('div');
  maintCard.style.cssText='background:var(--s2);border-radius:14px;padding:14px 16px';
  var componentsHtml='';
  (bike.components||[]).forEach(function(c, i){
    var statusColor = c.pct!=null ? (c.pct>=85?'#ef4444':c.pct>=60?'#f59e0b':'#22c55e') : (c.milesSince && c.dueEvery && c.milesSince/c.dueEvery>=0.85 ? '#ef4444' : '#22c55e');
    var detail = c.pct!=null ? c.pct+'% worn' : (c.milesSince!=null && c.dueEvery ? c.milesSince+' / '+c.dueEvery+' mi' : '');
    componentsHtml += '<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;'+(i>0?'border-top:1px solid var(--b1);':'')+'">'
      +'<span style="font-size:13px;color:var(--t1);font-weight:600">'+c.name+'</span>'
      +'<span style="font-size:12px;font-weight:700;color:'+statusColor+'">'+detail+'</span></div>';
  });
  maintCard.innerHTML='<div style="font-size:11px;color:var(--t3);font-weight:700;text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px">Maintenance</div>'
    +componentsHtml
    +(badge.label?'<div style="margin-top:10px;padding-top:10px;border-top:1px solid var(--b1);font-size:12px;color:'+(badge.color||'var(--t2)')+';font-weight:700">'+badge.label+'</div>':'');
  wrap.appendChild(maintCard);

  body.appendChild(wrap);
}

// -- AI ANALYSIS TAB: cross-signal insights correlating wind, power,
// nutrition, and historical comparisons - the differentiated analysis
// layer the reference design calls for, not just reporting raw numbers.
function renderRideAnalysisTab(body, r, idx, FTP, BWT){
  var wrap=document.createElement('div');
  wrap.style.cssText='padding:14px 16px';
  wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">Analyzing this ride against your history&hellip;</div>';
  body.appendChild(wrap);

  // Compare this ride to past rides on similar distance, and gather bike
  // context, so the prompt can produce genuine cross-signal comparisons
  // rather than restating this ride's own numbers back.
  var similarRides = (st.rides||[]).filter(function(ride, i){
    return i!==idx && !ride.deleted && ride.distance && r.distance && Math.abs(ride.distance-r.distance)<5 && ride.avgPwr;
  }).slice(0,5);

  var prompt = 'You are a cycling data analyst. Analyze this ride and produce genuine cross-signal insights, not just a restatement of the numbers. '
    +'THIS RIDE: '+(r.distance||'?')+'mi, avg power '+(r.avgPwr||'?')+'W, NP '+(r.np||'?')+'W, avg HR '+(r.avgHR||'?')+'bpm, TSS '+(r.tss||'?')+', elevation '+(r.elev||0)+'ft. '
    +'SIMILAR PAST RIDES (same rider, similar distance): '+similarRides.map(function(sr){
      return sr.date+': '+sr.distance+'mi, avg power '+(sr.avgPwr||'?')+'W, avg HR '+(sr.avgHR||'?')+'bpm';
    }).join('; ')+'. '
    +'Give 3-4 short bullet-style insights (each starting with "- "), each one connecting two different signals '
    +'(e.g. comparing this ride to a similar past one, noting if power was higher despite similar effort, or any other genuine pattern in the data provided). '
    +'Be specific and use the actual numbers given. If there is not enough data for a genuine comparison, say so plainly rather than inventing detail.';

  fetch('https://mikey-food-api2.mgrobinson07.workers.dev/claude',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({ model:'claude-sonnet-4-6', max_tokens:350, messages:[{role:'user',content:prompt}] })
  })
  .then(function(res){ return res.json(); })
  .then(function(d){
    var text = d.content && d.content[0] && d.content[0].text;
    renderAnalysisContent(wrap, text);
  })
  .catch(function(){
    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">Could not reach the analysis right now.</div>';
  });
}

function renderAnalysisContent(wrap, text){
  wrap.innerHTML='';
  if(!text){
    wrap.innerHTML='<div style="padding:40px 20px;text-align:center;color:var(--t3);font-size:13px">No analysis available for this ride.</div>';
    return;
  }
  var lines = text.split(String.fromCharCode(10)).map(function(l){ return l.trim(); }).filter(Boolean);
  var listGroup=document.createElement('div');
  listGroup.style.cssText='background:var(--s2);border-radius:14px;overflow:hidden';
  var any=false;
  lines.forEach(function(line, i){
    if(line.indexOf('- ')!==0) return;
    any=true;
    var row=document.createElement('div');
    row.style.cssText='padding:12px 16px;'+(i>0?'border-top:1px solid var(--b1);':'')+'font-size:13px;color:var(--t1);line-height:1.5';
    row.textContent=line.replace(/^-\s*/,'');
    listGroup.appendChild(row);
  });
  if(!any){
    wrap.innerHTML='<div style="background:var(--s2);border-radius:14px;padding:16px;font-size:13px;color:var(--t1);line-height:1.5">'+text+'</div>';
  } else {
    wrap.appendChild(listGroup);
  }
}

function deleteRide(idx, e){
  if(e) e.stopPropagation();
  var old = document.getElementById('delete-confirm');
  if(old) old.remove();
  var overlay = document.createElement('div');
  overlay.id = 'delete-confirm';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:500;display:flex;align-items:center;justify-content:center;padding:20px';
  var box = document.createElement('div');
  box.style.cssText = 'background:var(--s1);border-radius:18px;padding:24px;width:100%;max-width:320px;text-align:center';
  box.innerHTML = '<div style="font-size:17px;font-weight:800;color:var(--t1);margin-bottom:8px">Delete Ride?</div>'
    + '<div style="font-size:14px;color:var(--t2);margin-bottom:20px">This cannot be undone.</div>'
    + '<div style="display:flex;gap:10px">'
    + '<button onclick="document.getElementById(&quot;delete-confirm&quot;).remove()" style="flex:1;padding:12px;border:1px solid var(--b2);border-radius:12px;background:var(--s2);color:var(--t2);font-size:15px;font-weight:600;cursor:pointer;font-family:inherit">Cancel</button>'
    + '<button id="confirm-del-btn" style="flex:1;padding:12px;border:none;border-radius:12px;background:#E74C3C;color:white;font-size:15px;font-weight:700;cursor:pointer;font-family:inherit">Delete</button>'
    + '</div>';
  overlay.appendChild(box);
  document.body.appendChild(overlay);
  document.getElementById('confirm-del-btn').onclick = function(){
    overlay.remove();
    var ride = st.rides[idx];
    if(ride){
      // Tombstone instead of hard-delete (splice) - a plain removal can be
      // silently resurrected by the merge-safe sync pulling in an older
      // cloud snapshot that still has this ride, since a union-merge has
      // no way to know it was deleted on purpose. Same fix already
      // applied to nutrition entries.
      if(!ride.id) ride.id = genEntryId_();
      ride.deleted = true;
      ride.deletedAt = Date.now();
    }
    sv();
    fbPush(false, true); // push immediately as authoritative, so the deletion sticks right away rather than waiting on the next routine merge
    // If this delete was triggered from inside the ride detail view
    // itself (via the More menu), close it - the ride it was showing
    // no longer exists.
    var rideDetailModal=document.getElementById('ride-detail-modal');
    if(rideDetailModal) closeRideDetail();
    // Activities was folded into Analytics - the ride list lives in
    // analytics-ride-list now, a sub-container inside perf-body.
    var rlc=document.getElementById('analytics-ride-list');
    if(rlc){ renderRideList(rlc); }
    else{
      var perfBody=document.getElementById('perf-body');
      if(perfBody) renderPerf(perfBody);
    }
  };
}

function closeRideDetail(){
  var m = document.getElementById('ride-detail-modal');
  if(m) m.remove();
  document.body.style.overflow = '';
}

