function buildRouteMap(lats, lons, pwrData, FTP){
  if(!lats||!lats.length) return '';
  // Defensive guard against already-corrupted data (mismatched lat/lon
  // array lengths from before this was fixed at the merge level) - an
  // uncaught "Invalid LatLng object" error here would otherwise halt
  // the entire map render, leaving a blank container.
  if(lons && lons.length !== lats.length){
    var minLen = Math.min(lats.length, lons.length);
    lats = lats.slice(0, minLen);
    lons = lons.slice(0, minLen);
  }
  if(!lats.length) return '';
  // Generate unique map ID
  if(!window._mapCount) window._mapCount=0; window._mapCount++; var mapId = 'leaflet-map-' + window._mapCount;
  window._lastRouteMapId = mapId;
  var html = '<div id="'+mapId+'" style="width:100%;height:260px;border-radius:16px;overflow:hidden"></div>';

  // Initialize map after DOM insertion
  setTimeout(function(){
    var mapEl = document.getElementById(mapId);
    if(!mapEl) return;

    // Center on route
    var centerLat = (Math.min.apply(null,lats)+Math.max.apply(null,lats))/2;
    var centerLon = (Math.min.apply(null,lons)+Math.max.apply(null,lons))/2;

    var map = L.map(mapId, {
      zoomControl: true,
      scrollWheelZoom: false,
      tap: false
    });

    // OpenStreetMap tiles
    var baseOSM = L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© OpenStreetMap',
      maxZoom: 17
    }).addTo(map);
    // Expose this map + its base layer so external controls (e.g. the
    // Overview preview's layers button) can toggle satellite/street.
    window['_routeMap_'+mapId] = { map: map, base: baseOSM, sat: null, satOn: false };

    // Build color-coded polyline segments
    if(pwrData && pwrData.length > 5){
      var step = Math.max(1, Math.floor(lats.length/pwrData.length));
      var currentColor = '#94a3b8';
      var segPoints = [[lats[0], lons[0]]];

      for(var i=1; i<lats.length; i++){
        var pIdx = Math.floor(i/step);
        var pw = pwrData[Math.min(pIdx, pwrData.length-1)] || 0;
        var col = pw>=FTP*1.06?'#ef4444':pw>=FTP*.91?'#f59e0b':pw>=FTP*.76?'#22c55e':pw>=FTP*.56?'#3b82f6':'#94a3b8';

        if(col !== currentColor && segPoints.length > 1){
          L.polyline(segPoints, {color:currentColor, weight:4, opacity:0.85}).addTo(map);
          segPoints = [segPoints[segPoints.length-1]];
          currentColor = col;
        }
        segPoints.push([lats[i], lons[i]]);
      }
      if(segPoints.length > 1){
        L.polyline(segPoints, {color:currentColor, weight:4, opacity:0.85}).addTo(map);
      }
    } else {
      // Single orange line
      var coords = lats.map(function(lat,i){ return [lat, lons[i]]; });
      L.polyline(coords, {color:'#FC4C02', weight:4, opacity:0.9}).addTo(map);
    }

    // Start marker (green)
    L.circleMarker([lats[0], lons[0]], {
      radius:8, fillColor:'#27AE60', color:'white', weight:2, fillOpacity:1
    }).addTo(map);

    // End marker (orange)
    var le = lats.length-1;
    L.circleMarker([lats[le], lons[le]], {
      radius:8, fillColor:'#FC4C02', color:'white', weight:2, fillOpacity:1
    }).addTo(map);

    // Fit map to route
    var coords2 = lats.map(function(lat,i){return [lat,lons[i]];});
    var bounds = L.latLngBounds(coords2);
    map.invalidateSize();
    map.fitBounds(bounds, {padding:[30,30], maxZoom:14});
    // Re-invalidate shortly after too, in case the container's layout was
    // still settling (e.g. modal transition/animation) at the first check
    setTimeout(function(){ try{ map.invalidateSize(); }catch(e){} }, 300);

  }, 100);

  return html;
}


function buildLineChart(data, color, unit, label, refLine){
  if(!data||!data.length) return '';
  var W=600, H=100;
  var mn=Math.min.apply(null,data), mx=Math.max.apply(null,data);
  var rng=mx-mn||1;
  function sx(i){ return Math.round(10+(i/(data.length-1))*(W-20)); }
  function sy(v){ return Math.round(H-10-((v-mn)/rng)*(H-25)); }

  var path='M';
  data.forEach(function(v,i){ path+=(i?'L':'')+sx(i)+','+sy(v); });

  // Area fill
  var area=path+' L'+sx(data.length-1)+','+(H-10)+' L'+sx(0)+','+(H-10)+' Z';

  var svg='<svg viewBox="0 0 '+W+' '+H+'" style="width:100%;height:'+H+'px">';

  // Reference line (FTP)
  if(refLine){
    var ry=sy(refLine);
    if(ry>10&&ry<H-10){
      svg+='<line x1="10" y1="'+ry+'" x2="'+(W-10)+'" y2="'+ry+'" stroke="rgba(0,0,0,.15)" stroke-width="1" stroke-dasharray="4,3"/>';
      svg+='<text x="12" y="'+(ry-2)+'" font-size="8" fill="rgba(0,0,0,.4)" font-family="-apple-system,sans-serif">FTP</text>';
    }
  }

  svg+='<path d="'+area+'" fill="'+color+'" opacity=".1"/>';
  svg+='<path d="'+path+'" fill="none" stroke="'+color+'" stroke-width="2" stroke-linejoin="round"/>';

  // Min/Max labels
  svg+='<text x="'+(W-8)+'" y="18" text-anchor="end" font-size="9" fill="'+color+'" font-family="-apple-system,sans-serif">'+mx+unit+'</text>';
  svg+='<text x="'+(W-8)+'" y="'+(H-2)+'" text-anchor="end" font-size="9" fill="rgba(0,0,0,.4)" font-family="-apple-system,sans-serif">'+mn+unit+'</text>';

  svg+='</svg>';
  if(label) svg+='<div style="text-align:center;font-size:11px;color:var(--t3);margin-top:4px">'+label+'</div>';
  return svg;
}

function promptRideName(defaultName, callback){
  var old = document.getElementById('name-prompt-modal');
  if(old) old.remove();

  var overlay = document.createElement('div');
  overlay.id = 'name-prompt-modal';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:400;display:flex;align-items:center;justify-content:center;padding:20px';

  var box = document.createElement('div');
  box.style.cssText = 'background:var(--s1);border-radius:18px;padding:24px;width:100%;max-width:400px;box-shadow:0 8px 32px rgba(0,0,0,.2)';

  var title = document.createElement('div');
  title.style.cssText = 'font-size:17px;font-weight:800;color:var(--t1);margin-bottom:6px';
  title.textContent = 'Name this ride';

  var sub = document.createElement('div');
  sub.style.cssText = 'font-size:13px;color:var(--t3);margin-bottom:16px';
  sub.textContent = 'Edit the name before saving';

  var inp = document.createElement('input');
  inp.type = 'text';
  inp.value = defaultName || '';
  inp.style.cssText = 'width:100%;font-size:16px;font-weight:600;border:2px solid var(--b2);border-radius:12px;padding:12px 14px;background:var(--s2);color:var(--t1);font-family:inherit;margin-bottom:16px';
  inp.addEventListener('focus', function(){ this.style.borderColor='var(--orange)'; });
  inp.addEventListener('blur', function(){ this.style.borderColor='var(--b2)'; });

  var btns = document.createElement('div');
  btns.style.cssText = 'display:flex;gap:10px';

  var cancel = document.createElement('button');
  cancel.textContent = 'Cancel';
  cancel.style.cssText = 'flex:1;padding:12px;border:1px solid var(--b2);border-radius:12px;background:var(--s2);color:var(--t2);font-size:15px;font-weight:600;cursor:pointer;font-family:inherit';
  cancel.onclick = function(){ overlay.remove(); };

  var save = document.createElement('button');
  save.textContent = 'Save Ride';
  save.style.cssText = 'flex:2;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#FC4C02,#FF7043);color:white;font-size:15px;font-weight:700;cursor:pointer;font-family:inherit';
  save.onclick = function(){
    var name = inp.value.trim() || defaultName || 'Activity';
    overlay.remove();
    callback(name);
  };

  // Also save on Enter
  inp.addEventListener('keydown', function(e){ if(e.key==='Enter') save.onclick(); });

  btns.appendChild(cancel);
  btns.appendChild(save);
  box.appendChild(title);
  box.appendChild(sub);
  box.appendChild(inp);
  box.appendChild(btns);
  overlay.appendChild(box);
  document.body.appendChild(overlay);

  // Focus and select all
  setTimeout(function(){ inp.focus(); inp.select(); }, 100);
}

