function renderCond(){
  var existing=document.getElementById('COND-SCREEN');
  if(existing) existing.remove();

  var scr=document.createElement('div');
  scr.id='COND-SCREEN';
  scr.style.cssText='position:fixed;inset:0;bottom:60px;background:var(--bg);z-index:200;overflow-y:auto;padding-bottom:20px';

  var backBtn=document.createElement('button');
  backBtn.className='back-btn';
  backBtn.style.cssText='margin:16px';
  backBtn.style.display='';
  backBtn.onclick=function(){scr.remove();};
  scr.appendChild(backBtn);

  var title=document.createElement('div');
  title.style.cssText='padding:4px 16px 16px';
  title.innerHTML='<div style="font-size:22px;font-weight:800;color:var(--t1)">Conditioning</div>'
    +'<div style="font-size:13px;color:var(--t3);margin-top:4px">Battle rope · Jump rope · Med ball · Plyo box · Bands</div>';
  scr.appendChild(title);

  COND_GROUPS.forEach(function(g){
    var sec=document.createElement('div');
    sec.style.cssText='padding:0 16px';
    var glbl=document.createElement('div');
    glbl.style.cssText='font-size:12px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.8px;padding:10px 0 8px;border-top:1px solid var(--b1)';
    glbl.textContent=g.label;
    sec.appendChild(glbl);

    g.exs.forEach(function(ei){
      var ex=COND_EX[ei];
      var card=document.createElement('div');
      card.style.cssText='background:var(--s2);border-radius:12px;padding:12px 14px;margin-bottom:8px;border:1px solid var(--b2)';

      var topRow=document.createElement('div');
      topRow.style.cssText='display:flex;align-items:flex-start;justify-content:space-between;gap:8px';

      var info=document.createElement('div');
      info.style.cssText='flex:1';
      info.innerHTML='<div style="font-size:14px;font-weight:700;color:var(--t1);margin-bottom:3px;display:flex;align-items:center;gap:6px">'+ex[0]+'<a href="https://www.youtube.com/results?search_query='+encodeURIComponent(ex[0]+' exercise tutorial')+'" target="_blank" style="font-size:10px;color:#FF0000;text-decoration:none;display:inline-flex;align-items:center;gap:2px;font-weight:600">▶ watch</a></div>'
        +'<div style="font-size:11px;color:var(--t3);line-height:1.4;margin-bottom:6px">'+ex[4]+'</div>'
        +'<div style="display:flex;gap:8px;flex-wrap:wrap">'
        +'<span style="font-size:11px;background:var(--s3);border-radius:6px;padding:2px 8px;color:var(--orange);font-weight:700">'+ex[1]+' sets</span>'
        +'<span style="font-size:11px;background:var(--s3);border-radius:6px;padding:2px 8px;color:var(--t2)">'+ex[2]+(ex[6]?' work':' reps')+'</span>'
        +(ex[3]!=='—'?'<span style="font-size:11px;background:var(--s3);border-radius:6px;padding:2px 8px;color:var(--t2)">'+ex[3]+' rest</span>':'')
        +'</div>';

      var logBtn=document.createElement('button');
      logBtn.style.cssText='background:rgba(252,76,2,.1);border:1px solid rgba(252,76,2,.2);color:var(--orange);font-size:12px;font-weight:700;padding:8px 12px;border-radius:10px;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0';
      logBtn.textContent='Log';

      (function(capEx, capEi, capBtn){
        capBtn.onclick=function(){
          openCondLog(capEi, capBtn);
        };
      })(ex, ei, logBtn);

      topRow.appendChild(info);
      topRow.appendChild(logBtn);
      card.appendChild(topRow);

      // Log area (hidden by default)
      var logArea=document.createElement('div');
      logArea.id='cond-log-'+ei;
      logArea.style.display='none';
      card.appendChild(logArea);

      sec.appendChild(card);
    });
    scr.appendChild(sec);
  });

  document.body.appendChild(scr);
}

function openCondLog(ei, btn){
  var logArea=document.getElementById('cond-log-'+ei);
  if(!logArea) return;
  if(logArea.style.display==='block'){logArea.style.display='none';btn.textContent='Log';return;}

  var ex=COND_EX[ei];
  var today=getTodayKey();
  if(!st.cond) st.cond={};
  if(!st.cond[today]) st.cond[today]={};
  var saved=st.cond[today][ei]||{sets:[]};

  logArea.innerHTML='';
  logArea.style.cssText='margin-top:10px;padding-top:10px;border-top:1px solid var(--b1)';
  logArea.style.display='block';
  btn.textContent='Done ✓';

  var sets=parseInt(ex[1])||3;
  for(var si=0;si<sets;si++){
    var sd=saved.sets[si]||{};
    var row=document.createElement('div');
    row.style.cssText='display:flex;align-items:center;gap:8px;margin-bottom:6px';

    var setLbl=document.createElement('div');
    setLbl.style.cssText='font-size:12px;color:var(--t3);width:36px;flex-shrink:0';
    setLbl.textContent='Set '+(si+1);

    var valInp=document.createElement('input');
    valInp.type='number';
    valInp.placeholder=ex[6]?'secs':ex[2]+' reps';
    valInp.className='si';
    valInp.style.cssText='flex:1';
    if(sd.v) valInp.value=sd.v;

    var noteInp=document.createElement('input');
    noteInp.type='text';
    noteInp.placeholder='note';
    noteInp.className='si';
    noteInp.style.cssText='flex:1;font-size:11px';
    if(sd.note) noteInp.value=sd.note;

    var chk=document.createElement('div');
    chk.className='sc'+(sd.done?' on':'');
    if(sd.done) chk.textContent='v';

    (function(capEi, capSi, capChk){
      capChk.addEventListener('click',function(){
        var on=capChk.classList.contains('on');
        if(on){capChk.classList.remove('on');capChk.textContent='';}
        else{capChk.classList.add('on');capChk.textContent='v';}
        saveCondLog(capEi);
      });
    })(ei, si, chk);

    row.appendChild(setLbl);row.appendChild(valInp);row.appendChild(noteInp);row.appendChild(chk);
    logArea.appendChild(row);
  }

  var saveBtn=document.createElement('button');
  saveBtn.style.cssText='width:100%;margin-top:6px;background:rgba(252,76,2,.1);border:1px solid rgba(252,76,2,.2);color:var(--orange);font-size:13px;font-weight:700;padding:9px;border-radius:10px;cursor:pointer;font-family:inherit';
  saveBtn.textContent='Save Set';
  saveBtn.onclick=function(){saveCondLog(ei);toast('Saved!');};
  logArea.appendChild(saveBtn);
}

function saveCondLog(ei){
  var today=getTodayKey();
  if(!st.cond) st.cond={};
  if(!st.cond[today]) st.cond[today]={};
  var ex=COND_EX[ei];
  var sets=parseInt(ex[1])||3;
  var saved={sets:[]};
  for(var si=0;si<sets;si++){
    var ve=document.querySelector('#cond-log-'+ei+' input[type="number"]');
    var inputs=document.querySelectorAll('#cond-log-'+ei+' input');
    var chks=document.querySelectorAll('#cond-log-'+ei+' .sc');
    var vv=inputs[si*2]?inputs[si*2].value:'';
    var nv=inputs[si*2+1]?inputs[si*2+1].value:'';
    var done=chks[si]?chks[si].classList.contains('on'):false;
    saved.sets.push({v:vv,note:nv,done:done});
  }
  st.cond[today][ei]=saved;
  sv();
}

