// ── CORE MODULE ──────────────────────────────────────────────────────────────
// [name, sets, reps/hold, cue, isTimeBased]
var CORE_EX = [
  // Obliques
  ['Side Plank',              '3', '30s', 'Body straight, hips up — no sagging. Progress to 60s', true],
  ['Pallof Press',            '3', '12',  'Stand sideways to anchor, press straight out — resist rotation', false],
  ['Russian Twist',           '3', '20',  'Lean back 45°, rotate shoulder to floor each side — add weight to progress', false],
  ['Bicycle Crunch',          '3', '20',  'Slow and controlled — elbow to opposite knee, full rotation', false],
  ['Woodchop',                '3', '10',  'Band or cable, high to low diagonal — rotate through hips not just arms', false],
  ['Suitcase Carry',          '3', '40s', 'Heavy weight one side only, walk tall — do not lean into the weight', true],
  // Deep core / TVA
  ['Dead Bug',                '3', '10',  'Per side — lower back pressed flat, extend opposite arm and leg slowly', false],
  ['Hollow Body Hold',        '3', '20s', 'Lower back glued to floor, legs low, arms overhead — shake is good', true],
  ['Bear Crawl Hold',         '3', '30s', 'All fours, knees 1 inch off ground — breathe normally, stay rigid', true],
  // Lower back / erectors
  ['Superman Hold',           '3', '10',  'Lift arms and legs simultaneously, hold 2s at top each rep', false],
  ['Bird Dog',                '3', '10',  'Per side — extend opposite arm and leg, pause 2s, no hip rotation', false],
  ['Good Mornings',           '3', '12',  'Bodyweight — hinge at hips, soft knees, feel the hamstrings load', false],
  // Cycling-specific
  ['Single-Leg Glute Bridge', '3', '12',  'Per side — drive heel into floor, squeeze glute at top, hips level', false],
  ['Copenhagen Plank',        '3', '20s', 'Top leg on bench, bottom leg hanging — oblique and adductor together', true],
];

var curCoreW = 1;

function showCore(){ renderCore(); }

function openCore(w){
  curCoreW = w;
  var modal = document.getElementById('mod-CORE');
  var s = ws(w);
  if(!s.core) s.core = {};

  modal.innerHTML = '';
  var sheet = document.createElement('div');
  sheet.className = 'modal-sh';

  var hdl = document.createElement('div'); hdl.className = 'mhdl'; sheet.appendChild(hdl);

  var hdr = document.createElement('div'); hdr.className = 'mhdr';
  var htxt = document.createElement('div');
  htxt.innerHTML = '<div class="mtit">Core Training</div><div style="font-size:12px;color:var(--t3)">Week ' + w + '</div>';
  var xbtn = document.createElement('button');
  xbtn.className = 'mclose'; xbtn.textContent = '✕';
  xbtn.addEventListener('click', function(){ closeCore(); });
  hdr.appendChild(htxt); hdr.appendChild(xbtn);
  sheet.appendChild(hdr);

  // Group labels
  var groups = [
    {label:'🌀 Obliques', range:[0,5]},
    {label:'🔒 Deep Core / TVA', range:[6,8]},
    {label:'🦴 Lower Back', range:[9,11]},
    {label:'🚴 Cycling Core', range:[12,13]}
  ];

  CORE_EX.forEach(function(ex, ei){
    // Add group header if needed
    groups.forEach(function(g){
      if(ei === g.range[0]){
        var glbl = document.createElement('div');
        glbl.style.cssText = 'font-size:11px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.8px;padding:14px 16px 6px';
        glbl.textContent = g.label;
        sheet.appendChild(glbl);
      }
    });

    var card = document.createElement('div'); card.className = 'ex-c';
    var exhdr = document.createElement('div'); exhdr.className = 'ex-h';
    var exinfo = document.createElement('div');
    var exnm = document.createElement('div'); exnm.className = 'ex-nm'; exnm.textContent = ex[0];
    var extip = document.createElement('div'); extip.className = 'ex-tip'; extip.textContent = ex[3];
    exinfo.appendChild(exnm); exinfo.appendChild(extip);
    exhdr.appendChild(exinfo);
    card.appendChild(exhdr);

    var colhdr = document.createElement('div'); colhdr.className = 'set-hr';
    var isTime = ex[4];
    colhdr.innerHTML = '<div class="sn" style="font-size:10px;color:var(--t3)">SET</div>'
      + '<div class="sp" style="font-size:10px;color:var(--t3)">PREV</div>'
      + '<div style="font-size:10px;color:var(--t3);text-align:center">' + (isTime ? 'SECS' : 'REPS') + '</div>'
      + '<div style="font-size:10px;color:var(--t3);text-align:center">NOTES</div>'
      + '<div></div>';
    card.appendChild(colhdr);

    var sets = parseInt(ex[1]) || 3;
    for(var si = 0; si < sets; si++){
      var sd = (s.core[ei] && s.core[ei][si]) || {};
      var prev = getCoreP(w, ei, si);

      var row = document.createElement('div');
      row.className = 'set-r' + (sd.done ? ' done' : '');
      row.id = 'core_r_' + ei + '_' + si;

      var snum = document.createElement('div'); snum.className = 'sn'; snum.textContent = si + 1;
      var sprev = document.createElement('div'); sprev.className = 'sp';
      sprev.style.cssText = 'color:var(--blue);font-size:11px;font-weight:600';
      sprev.textContent = prev;

      var rinp = document.createElement('input');
      rinp.type = 'number';
      rinp.placeholder = isTime ? 'secs' : ex[2];
      rinp.className = 'si';
      rinp.id = 'core_v_' + ei + '_' + si;
      if(sd.v) rinp.value = sd.v;

      var ninp = document.createElement('input');
      ninp.type = 'text';
      ninp.placeholder = 'note';
      ninp.className = 'si';
      ninp.style.cssText += ';font-size:11px';
      ninp.id = 'core_n_' + ei + '_' + si;
      if(sd.note) ninp.value = sd.note;

      var chk = document.createElement('div');
      chk.className = 'sc' + (sd.done ? ' on' : '');
      chk.id = 'core_c_' + ei + '_' + si;
      if(sd.done) chk.textContent = 'v';

      (function(capEi, capSi, capChk, capRow){
        capChk.addEventListener('click', function(){
          var on = capChk.classList.contains('on');
          if(on){ capChk.classList.remove('on'); capChk.textContent = ''; capRow.classList.remove('done'); }
          else { capChk.classList.add('on'); capChk.textContent = 'v'; capRow.classList.add('done'); }
          savCore();
        });
      })(ei, si, chk, row);

      row.appendChild(snum); row.appendChild(sprev); row.appendChild(rinp); row.appendChild(ninp); row.appendChild(chk);
      card.appendChild(row);
    }
    sheet.appendChild(card);
  });

  var finbtn = document.createElement('button');
  finbtn.className = 'fin-btn'; finbtn.textContent = 'Finish Core v';
  finbtn.addEventListener('click', function(){ finCore(); });
  sheet.appendChild(finbtn);

  modal.appendChild(sheet);
  modal.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function getCoreP(w, ei, si){
  for(var pw = w-1; pw >= 1; pw--){
    var ps = ws(pw);
    if(ps.core && ps.core[ei] && ps.core[ei][si] && ps.core[ei][si].v)
      return ps.core[ei][si].v + (CORE_EX[ei][4] ? 's' : ' reps');
  }
  return '-';
}

function savCore(){
  var s = ws(curCoreW);
  if(!s.core) s.core = {};
  for(var ei = 0; ei < CORE_EX.length; ei++){
    if(!s.core[ei]) s.core[ei] = {};
    var sets = parseInt(CORE_EX[ei][1]) || 3;
    for(var si = 0; si < sets; si++){
      var ve = document.getElementById('core_v_' + ei + '_' + si);
      var ne = document.getElementById('core_n_' + ei + '_' + si);
      var ce = document.getElementById('core_c_' + ei + '_' + si);
      s.core[ei][si] = {
        v: ve ? ve.value : '',
        note: ne ? ne.value : '',
        done: ce ? ce.classList.contains('on') : false
      };
    }
  }
  sv();
}

function finCore(){
  savCore();
  closeCore();
  toast('Core session done! 🔥');
}

function closeCore(){
  document.getElementById('mod-CORE').classList.remove('open');
  document.body.style.overflow = '';
}

function renderCore(){
  // Show core as a simple screen with current week button
  var existing = document.getElementById('CORE-SCREEN');
  if(existing) existing.remove();

  var scr = document.createElement('div');
  scr.id = 'CORE-SCREEN';
  scr.style.cssText = 'position:fixed;inset:0;background:var(--bg);z-index:300;overflow-y:auto;padding-bottom:40px';

  var backBtn = document.createElement('button');
  backBtn.className = 'back-btn';
  backBtn.style.cssText = 'margin:16px';
  backBtn.textContent = '← Back';
  backBtn.onclick = function(){ scr.remove(); };
  scr.appendChild(backBtn);

  var title = document.createElement('div');
  title.style.cssText = 'padding:4px 16px 16px';
  title.innerHTML = '<div style="font-size:22px;font-weight:800;color:var(--t1)">Core Training</div>'
    + '<div style="font-size:13px;color:var(--t3);margin-top:4px">Sets · Reps · Hold times — logged per week</div>';
  scr.appendChild(title);

  // Exercise list preview
  var groups = [
    {label:'🌀 Obliques', exs:[0,1,2,3,4,5]},
    {label:'🔒 Deep Core / TVA', exs:[6,7,8]},
    {label:'🦴 Lower Back', exs:[9,10,11]},
    {label:'🚴 Cycling Core', exs:[12,13]}
  ];

  groups.forEach(function(g){
    var sec = document.createElement('div');
    sec.style.cssText = 'padding:0 16px';
    var glbl = document.createElement('div');
    glbl.style.cssText = 'font-size:11px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.8px;padding:12px 0 8px';
    glbl.textContent = g.label;
    sec.appendChild(glbl);

    g.exs.forEach(function(ei){
      var ex = CORE_EX[ei];
      var done = false;
      var s = ws(cw);
      if(s.core && s.core[ei]){
        var sets = parseInt(ex[1])||3;
        var allDone = true;
        for(var si=0;si<sets;si++){ if(!s.core[ei][si]||!s.core[ei][si].done) allDone=false; }
        done = allDone;
      }
      var card = document.createElement('div');
      card.style.cssText = 'background:var(--s2);border-radius:12px;padding:12px 14px;margin-bottom:6px;border:1px solid '+(done?'rgba(0,200,150,.3)':'var(--b2)')+';display:flex;align-items:center;gap:10px';
      card.innerHTML = '<div style="width:22px;height:22px;border-radius:50%;background:'+(done?'var(--green)':'var(--s3)')+';display:flex;align-items:center;justify-content:center;flex-shrink:0">'
        +(done?'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3"><polyline points="20 6 9 17 4 12"/></svg>':'')+'</div>'
        +'<div style="flex:1"><div style="font-size:13px;font-weight:700;color:var(--t1);display:flex;align-items:center;gap:6px">'+ex[0]+'<a href="https://www.youtube.com/results?search_query='+encodeURIComponent(ex[0]+' exercise tutorial')+'" target="_blank" style="font-size:10px;color:#FF0000;text-decoration:none;font-weight:600">▶</a></div>'
        +'<div style="font-size:11px;color:var(--t3)">'+ex[1]+' sets · '+ex[2]+(ex[4]?' hold':' reps')+'</div></div>';
      sec.appendChild(card);
    });
    scr.appendChild(sec);
  });

  // Log button
  var logWrap = document.createElement('div');
  logWrap.style.cssText = 'padding:20px 16px 0';
  var logBtn = document.createElement('button');
  logBtn.style.cssText = 'width:100%;background:var(--orange);border:none;color:#fff;font-size:15px;font-weight:800;padding:16px;border-radius:14px;cursor:pointer;font-family:inherit;letter-spacing:.3px';
  logBtn.textContent = 'Log Core Session — Week ' + cw;
  logBtn.onclick = function(){ openCore(cw); };
  logWrap.appendChild(logBtn);
  scr.appendChild(logWrap);

  document.body.appendChild(scr);
}

