var BIKE_PHOTO_DOGMA = 'data:image/jpeg;base64,';
var BIKE_PHOTO_ROADMACHINE = 'data:image/jpeg;base64,';
var BIKE_PHOTO_ZWIFT = 'data:image/jpeg;base64,';

// Recomputes mileage for Zwift Ride (via Strava's trainer flag) and any
// shoe whose Strava gear_id is known (via st.stravaGearMap, populated by
// syncStravaGear()). Sums fresh from st.rides/st.runs each time rather than
// incrementing per-ride, so re-syncing never double-counts.
function recomputeGearMileage(){
  if(st.bikes){
    var zwift = st.bikes.find(function(b){ return b.indoor; });
    if(zwift){
      // Include trainer rides from both direct Strava sync and ICU CSV import -
      // both paths now capture the trainer flag, so neither source should be
      // silently excluded from Zwift Ride mileage.
      var indoorMiles = (st.rides||[]).filter(function(r){
        return !r.deleted && r.trainer && (r.source==='strava' || r.source==='intervals');
      }).reduce(function(sum,r){ return sum + (r.distance||0); }, 0);
      zwift.miles = Math.round(indoorMiles*10)/10;
    }
  }

  if(st.shoes){
    st.shoes.forEach(function(shoe){
      // Strava-synced rides: match by gear_id via the gear map fetched from Strava's API
      var gearId = null;
      if(st.stravaGearMap){
        gearId = Object.keys(st.stravaGearMap).find(function(gid){
          return st.stravaGearMap[gid] === shoe.name;
        });
      }
      // ICU CSV-imported rides: ICU doesn't expose Strava's raw gear_id, but
      // does export the gear's display name directly - match on that instead.
      var shoeMiles = (st.rides||[]).filter(function(r){
        if(r.deleted) return false;
        if(gearId && r.gearId === gearId) return true;
        if(r.gearName && r.gearName === shoe.name) return true;
        return false;
      }).reduce(function(sum,r){ return sum + (r.distance||0); }, 0);
      if(shoeMiles > 0) shoe.miles = Math.round(shoeMiles*10)/10;
    });
  }

  sv();
}

// Fetches the athlete's registered gear (bikes + shoes) from Strava,
// so we can map gear_id -> real name and attribute mileage correctly.
// Requires an existing valid Strava token (from stravaBackfill()).
function fetchStravaElevStats(silent){
  if(!st.stravaToken){ if(!silent) toast('Sync Strava first to get a token'); return; }
  if(!silent) toast('Fetching elevation stats from Strava...');
  function doFetch(athleteId){
    fetch('https://www.strava.com/api/v3/athletes/'+athleteId+'/stats',{
      headers:{'Authorization':'Bearer '+st.stravaToken}
    }).then(function(r){
      if(r.status===401){ if(!silent) toast('Strava token expired — tap Sync Strava first'); return null; }
      return r.ok?r.json():null;
    })
    .then(function(s){
      if(!s){ if(!silent) toast('Could not read elevation stats from Strava'); return; }
      var ytd = s.ytd_ride_totals&&s.ytd_ride_totals.elevation_gain ? Math.round(s.ytd_ride_totals.elevation_gain*3.28084) : null;
      var all = s.all_ride_totals&&s.all_ride_totals.elevation_gain ? Math.round(s.all_ride_totals.elevation_gain*3.28084) : null;
      if(ytd||all){
        st.stravaElevStats={ytd:ytd, allTime:all, fetchedAt:Date.now()};
        sv();
        if(!silent) toast('Updated: '+(ytd?ytd.toLocaleString()+' ft YTD':'')+(all?' / '+all.toLocaleString()+' ft all-time':''));
      } else {
        if(!silent) toast('No elevation data returned from Strava');
      }
    }).catch(function(e){ if(!silent) toast('Strava error: '+(e&&e.message?e.message:'network')); });
  }
  if(st.stravaAthleteId){ doFetch(st.stravaAthleteId); return; }
  fetch('https://www.strava.com/api/v3/athlete',{headers:{'Authorization':'Bearer '+st.stravaToken}})
  .then(function(r){
    if(r.status===401){ if(!silent) toast('Strava token expired — run Sync Strava first then try Elev Stats'); return null; }
    if(!r.ok){ if(!silent) toast('Strava /athlete returned HTTP '+r.status); return null; }
    return r.json();
  })
  .then(function(a){
    if(!a) return;
    if(a&&a.id){ st.stravaAthleteId=a.id; sv(); doFetch(a.id); }
    else { if(!silent) toast('No athlete ID in response — keys: '+(a?JSON.stringify(Object.keys(a)):'null')); }
  })
  .catch(function(e){ if(!silent) toast('Strava error: '+(e&&e.message?e.message:'network')); });
}

function syncStravaGear(){
  if(!st.stravaToken){ toast('Sync Strava first to get a token'); return; }
  toast('Fetching your Strava gear...');
  fetch('https://www.strava.com/api/v3/athlete', {
    headers: { 'Authorization': 'Bearer ' + st.stravaToken }
  }).then(function(r){
    if(r.status === 401){ toast('Strava token expired — tap Sync Strava first'); return null; }
    if(!r.ok){ toast('Strava HTTP ' + r.status); return null; }
    return r.json();
  }).then(function(athlete){
    if(!athlete) return;
    var gearMap = {};
    (athlete.shoes||[]).forEach(function(s){ gearMap[s.id] = s.name; });
    (athlete.bikes||[]).forEach(function(b){ gearMap[b.id] = b.name; });
    st.stravaGearMap = gearMap;
    sv();
    var shoeCount = (athlete.shoes||[]).length;
    var bikeCount = (athlete.bikes||[]).length;
    toast('Synced '+shoeCount+' shoes, '+bikeCount+' bikes from Strava');
    recomputeGearMileage();
  }).catch(function(){ toast('Network error fetching gear'); });
}

function ensureBikes(){
  var defaults = [
    {id:'dogma-f', name:'Dogma F', type:'Race bike', brand:'Pinarello', groupset:'Shimano Ultegra', wheelset:'Campagnolo Bora WTO 60 C23',
      photo:BIKE_PHOTO_DOGMA,
      miles:2483, elevationFt:124000, longestMi:104, avgSpeed:19.8,
      components:[
        {name:'Chain', metric:'Wax', milesSince:132, dueEvery:150},
        {name:'Rear tire', metric:'Wear', pct:72},
        {name:'Brake pads', metric:'Wear', pct:84}
      ]},
    {id:'roadmachine', name:'Roadmachine', type:'Endurance bike', brand:'BMC', groupset:'', wheelset:'Black Inc Forty Five',
      photo:BIKE_PHOTO_ROADMACHINE,
      miles:741, elevationFt:0, longestMi:0, avgSpeed:0,
      components:[
        {name:'Rear tire', metric:'Wear', pct:40},
        {name:'Chain', metric:'Wax', milesSince:20, dueEvery:150}
      ]},
    {id:'zwift-ride', name:'Zwift Ride', type:'Indoor smart trainer', brand:'Zwift', groupset:'', wheelset:'',
      photo:BIKE_PHOTO_ZWIFT,
      miles:0, elevationFt:0, longestMi:0, avgSpeed:0, indoor:true,
      components:[]}
  ];

  if(!st.bikes || !st.bikes.length){
    st.bikes = defaults;
    sv();
    return;
  }

  var changed = false;
  defaults.forEach(function(def){
    var existing = st.bikes.find(function(b){ return b.id === def.id; });
    if(!existing){
      // Bike missing entirely (e.g. Zwift Ride added after initial seed) - add it
      st.bikes.push(def);
      changed = true;
    } else if(!existing.photo || existing.photo.indexOf('raw.githubusercontent.com') !== -1){
      // Backfill photo/indoor fields onto bikes saved before this update, preserving mileage/components.
      // Also upgrades bikes that got the old (CSP-blocked) GitHub-hosted photo URL to the new embedded base64 version.
      existing.photo = def.photo;
      if(def.indoor) existing.indoor = true;
      changed = true;
    }
  });

  if(changed) sv();
}

